// ****************************************************************************
// time command
// ****************************************************************************
time_t comp_time( time_t *tp ){
  time_t timer;
  timer=time( (time_t *)NULL );
#ifdef V4K5KTESTER
  timer += V4V5K_TIME_OFS;
  // Add Second of 16Hour (From U.S.)
#endif
  if( tp!=NULL ){
    *tp=timer;
  }
  return timer;
}


char *comp_ctime( time_t *tp ){
#ifdef V4K5KTESTER
  int i;
  int flag;
  int len;
  char *top;
  char *current;
  top = ctime((CTIME_T*) tp);
  if(NULL==top){
    return(NULL);
  }
  current = top;
  len = strlen(top);
  flag = OFF;
  for( i=0; i<len; i++ ){
    if( isalpha( *(current+i) ) ){
      if( OFF==flag ){
        flag = ON;
      }else if( ON==flag ){
        *(current+i) = (char)tolower( *(current+i) );
      }
    }else{
      flag = OFF;
    }
  }
  return( top );
#else
  return( ctime(tp) );
#endif
}

#endif

