      sprintf( replace_str, "decr%s", find_str+3 );
  }else if ((find_str = strstr(temp_buf, "fbm")) != NULL){
      sprintf( replace_str, "decr%s", find_str+3 );
  }else if ((find_str = strstr(temp_buf, "mbm")) != NULL){
      sprintf( replace_str, "mecr%s", find_str+3 );
  }else{
      sprintf( replace_str, temp_buf );
