int DeviceLevelsPowerUp(int vcc0,int vcc1,int vcc2,int relay)
{
  int err_flag;
  err_flag = PASS;

      // ** Power level check **
  if( ((vcc0 <=WAR_MAX_VCC ) & (vcc0 >=WAR_MIN_VCC ))               ); else err_flag |= 0x0002;
  if( ((vcc1 <=WAR_MAX_VDDH) & (vcc1 >=WAR_MIN_VDDH)) | (vcc1 == 0 )); else err_flag |= 0x0004;
  if( ((vcc2 <=WAR_MAX_VDD ) & (vcc2 >=WAR_MIN_VDD )) | (vcc2 == 0 )); else err_flag |= 0x0008;
  if( CheckFK(FK_DISP_DEBUG) ){
    sprintf(outbuf,"Power Setting  Vcc[0]=%d, vcc[1]=%d, vcc[2]=%d", vcc0,vcc1,vcc2 );
    DataOut(Ffpt,outbuf);
  }

  if( PASS!=err_flag ){ printf("-- FAIL -- vcc, ext_vrefH, ext_vref level over limit Error[0x%X]", err_flag ); return( err_flag ); }
  // ** current control?? **
#else
  if( comp_set_i1limit( 400000000 ) ) err_flag |= 0x0020;
  // V4000 500mA / V5000 PPS12 200mA(100mA?) / V5000 PPS12E 400mA
#endif
  if( comp_set_i2limit( 200000000 ) ) err_flag |= 0x0040;
  if( comp_set_i3limit( 200000000 ) ) err_flag |= 0x0080;
  if( comp_set_i4limit( 200000000 ) ) err_flag |= 0x0100;

        // ** Power Setting **
  if( comp_set_v1(vcc0)  ){ err_flag |= 0x0200; DeviceLevelsPowerDown(); }
  //Vcc setting
  if( comp_set_v3(vcc2)  ){ err_flag |= 0x0400; DeviceLevelsPowerDown(); }
  //ext_vref setting
  if( set_vih2(vcc1)     ){ err_flag |= 0x1000; DeviceLevelsPowerDown(); }
  //ext_vrefh setting
  disconnect_pin(monitor_vdd_pin);
  disconnect_pin(monitor_vddh_pin);

  delay_timer(30*1000);
  // 100ms = 100*1000us Wait
  if( PASS!=err_flag ){ printf("-- FAIL -- Vcc Set Error[0x%X]", err_flag ); return( err_flag ); }
  // ** LogicPin Setting **
  if( PASS!=err_flag   )   { printf("-- FAIL -- vih1&2,vhh Set Error[0x%X]", err_flag ); return( err_flag ); }
  // ** voh,vol Setting **
  if( set_vol(vcc0*1/2) ){ err_flag |= 0x8000; DeviceLevelsPowerDown(); }
  if( PASS!=err_flag )  { printf("-- FAIL -- Voh Vol Set Error[0x%X]", err_flag );}
  // ** Relay Setting **

    // Relay Status print
  if( CheckFK(FK_DISP_DEBUG) ){
    if(relay & 0x01) DataOut( Ffpt, " LB0 = ON  ");else DataOut( Ffpt, " LB0 = OFF  ");
    if(relay & 0x02) DataOut( Ffpt, " LB1 = ON\n");else DataOut( Ffpt, " LB1 = OFF\n");
    if(relay & 0x04) DataOut( Ffpt, " LB2 = ON  ");else DataOut( Ffpt, " LB2 = OFF  ");
    if(relay & 0x08) DataOut( Ffpt, " LB3 = ON\n");else DataOut( Ffpt, " LB3 = OFF\n");
  }

    // Relay Set
  comp_write_lbreg_pe(relay);
  reconnect_pin(all_pins);
  disconnect_pin(monitor_vdd_pin);
  disconnect_pin(monitor_vddh_pin);

  run_apg(_RELAY_SET);
  if( CheckFK(FK_DISP_DEBUG) ){
    DataOut(Ffpt,"Relay Set\n");
  }

  return( err_flag );
}

