 // *********************************************************************** SelectPowerSupply Function ***********************************************************************
int SelectPowerSupply(int mode,int vcc[NUM_POWERSUPPLY])
{
  int relay;
    // --------------------------------------------------------------------------
    // Initialyze
    // --------------------------------------------------------------------------
  relay = 0;

    // --- Relay Set ---//  
  if((CRYSTAL_MODE & 0x10000) == (mode & 0x10000)){
        //if((MNORMAL_CRS & 0xFF) == (mode & 0xFF))          relay = RNORMAL_CRS;    //0xfff0
    if((MNORMAL_CRS & 0xFF) == (mode & 0xFF))          relay = RVSSMON_20_CRS;
    //0xfff5
    else if((MVSSMON_CRS & 0xFF) == (mode & 0xFF))     relay = RVSSMON_CRS;
    //0xfff1
    else if((MVSSMON_20_CRS & 0xFF) == (mode & 0xFF))  relay = RVSSMON_20_CRS;
    //0xfff5
    else if((MVCCMON_CRS & 0xFF) == (mode & 0xFF))     relay = RVCCMON_CRS;
    //0xfff0
    else if((MVRSGMON_CRS & 0xFF) == (mode & 0xFF))    relay = RVRSGMON_CRS;
    //0xfff2
    else if((MVSSMON_CH_CRS & 0xFF) == (mode & 0xFF))  relay = RVSSMON_CH_CRS;
    //0xfff0
    else printf("-- FAIL -- mode set err");
    }
  else{
        //if(MNORMAL & mode)              relay = RNORMAL;        //0xfff8
    if(MNORMAL & mode)              relay = RVSSMON_20;
    //0xfffd                            // SW�ؑւ�������VCCMON,VSSMON���j�^�\�Ȃ悤�Ƀf�t�H���g�ύX�{SB��20k����R����O��Floating
    else if(MVSSMON & mode)         relay = RVSSMON;
    //0xfff9
    else if(MVSSMON_20 & mode)      relay = RVSSMON_20;
    //0xfffd
    else if(MVCCMON & mode)         relay = RVCCMON;
    //0xfff8
    else if(MVRSGMON & mode)        relay = RVRSGMON;
    //0xfffa
    else if(MVSSMON_CH & mode)      relay = RVSSMON_CH;
    //0xfff8
    else if(MVCLMON & mode)         relay = RVCLMON;
    else printf("-- FAIL -- mode set err");
}
  if(DeviceLevelsPowerUp(vcc[0],vcc[1],vcc[2],relay)) return(FAIL);
  return(PASS);
}

