int OpensShorts(void)
{
int status;

  printf("TEST:%d Opens/Shorts ",test);
  read_adc(0x11,0);
  // connect PMU(IMEAS)
  DeviceSpecificPowerDown();
  run_apg(_OPENS_SHORTS);
  reconnect_pin(os_pins);
  // set PPMUSEL=0,TRISTATE=1

  pmu_delay(1000);
  // wait=100usec
                                      // need wait 1ms for settling
  set_pmu_range(UA25);
  // max=25uA
  set_vlimit(-1500);
  // set input voltage = -1.5V
  comp_set_ilimit(10000);
  // I-Limit = 10000nA(10uA)

//  comp_set_cvpar (-1000);
// D

  status = seq_pmu_test_vlog(os_pins,0x10);
  if(status) {
    comp_set_cvpar (0);
    DeviceSpecificPowerDown();
    disp_pinvlog(0x03,0x03,0x01, os_pins,"-- open --");
    printf("-- FAIL(open) --");
    return(0x01);
  }

  comp_set_cvpar (20);

  status = seq_pmu_test_vlog(os_pins,0x20);
  set_vlimit(0);

  comp_set_cvpar (0);

  run_apg(_OPENS_SHORTS_END);

  DeviceSpecificPowerDown();
  if(status) {
    disp_pinvlog(0x03,0x03,0x01,os_pins,"-- short --");
    printf("-- FAIL(short) --");
    return(0x02);
  }
  printf("** PASS **");
  return(PASS);
