  //180314 Add-morioka For RamBoot
  reconnect_pin(poll_pins);
  //180314 Add-morioka For RamBoot

    // ** Test Speed SetUp **
  SetTimming_NS(speed);
  ChangeTimming_GTSLTS( EXTCYLJ, 1, MODEENTRY_SPEED );
  // ModeEntry���g���ݒ� GTS=1,20MHz

    // ******* APG SetUp(Power) ********
  tempo1=0;
  if((vcc[1] != 0) && (vcc[2] != 0)){
    tempo1 = tempo1 + 0x01;
    //ext_vref ON
    sprintf(outbuf," Ext_Vref  ON  ");
    DataOut(Ffpt,outbuf);
  }else{
    sprintf(outbuf," Ext_Vref  OFF ");
    DataOut(Ffpt,outbuf);
  }

    // ******* APG SetUp(Wait) ********
  load_vlf_offset(_SUB_MODEENTRY_RAM,6,  3*1000/MODEENTRY_SPEED);
  // 1us Wait
  load_vlf_offset(_SUB_MODEENTRY_RAM,1,300000/2/MODEENTRY_SPEED);
  // 300us Wait
  load_vlf_offset(_SUB_MODEENTRY_RAM,2, 70000/MODEENTRY_SPEED);
  // 70ms Wait
  load_vlf_offset(_SUB_MODEENTRY_RAM,3,tempo1);
  // Vdd/Vddh On/Off
  load_vlf_offset(_SUB_RAMBT_END,0,1);
  // RAMBootEnd Wait = waittime x(500x200x2000ns)
  load_vlf_offset(_SUB_RAMBT_POLL,0,500*waittime/speed);
  // RAMBootPoll Wait = waittime x(500x200x200ns)


  SetVohVolVtt( 15*vcc[0]/100, 15*vcc[0]/100, 5*vcc[0]/10 , bistpoll_pins );
  //�I�[��R�⃍�W�J��Pin��H/L����̓d���ݒ�(DAXS�]���p)

    // ************** PMU Setting *******************

  sprintf(outbuf,"  PMU Set");
  DataOut(Ffpt,outbuf);

  if((monitor_mode & ADC_DIGI) !=0){

    printf("APG : ADC_DIGI mode");

    load_vlf_offset(_SUB_RAMBT_POLL,0,waittime);

    load_vlf_offset(_SUB_MODEENTRY_RAM_CRY,6,  3*1000/MODEENTRY_SPEED);
    // 1us Wait
    load_vlf_offset(_SUB_MODEENTRY_RAM_CRY,1,300000/2/MODEENTRY_SPEED);
    // 300us Wait
    load_vlf_offset(_SUB_MODEENTRY_RAM_CRY,2, 100/MODEENTRY_SPEED);
    // 70ms Wait
    load_vlf_offset(_SUB_MODEENTRY_RAM_CRY,3,tempo1);
    // Vdd/Vddh On/Off

    run_apg(_RAM_BOOT_MONITOR_CRY);


  if((monitor_mode & CRY_CLK) !=0){
        // --- CRY CLK mode ---//
    sprintf(outbuf,"CRY CLK Set");
    DataOut(Ffpt,outbuf);
    remove_vhh_mask( lb3_pin );
    run_apg(_RAM_BOOT_RELAY);
  }

    delay_timer(1*1000);
    //1ms wait

    set_pps_resource(PPS_PMU_IRNG,PPS_50mA_RNG);
    //PMU 50mA Setting
    set_pps_resource(PPS_PMU_ILIMIT,50*1000*1000);
    //PMU ILIMIT = 50mA

      set_pps_resource(PPS_PMU_SENSE_CTRL,
      // PPS_REMOTE_SENSE
      delay_timer(1*1000);
      //1ms wait

      PMU_ADCDIGI_OUT(1,param,mess);

      delay_timer(1*1000);
      //1ms wait
      set_pps_resource(PPS_PMU_SENSE_CTRL,PPS_LOCAL_SENSE);

    set_pps_resource(PPS_PMU_IRNG,PPS_50mA_RNG);
    //PMU 50mA Setting
    set_pps_resource(PPS_PMU_ILIMIT,50*1000*1000);
    //PMU ILIMIT = 50mA


  }else if((monitor_mode & ADC_AVE) !=0){

    printf("APG : ADC_AVE mode");

    load_vlf_offset(_SUB_RAMBT_POLL,0,1);


    run_apg(_RAM_BOOT_MONITOR_CTRL);

    delay_timer(1*1000);
    //1ms wait

    set_pps_resource(PPS_PMU_IRNG,PPS_50mA_RNG);
    //PMU 50mA Setting
    set_pps_resource(PPS_PMU_ILIMIT,50*1000*1000);
    //PMU ILIMIT = 50mA

      set_pps_resource(PPS_PMU_SENSE_CTRL,
      // PPS_REMOTE_SENSE
      delay_timer(1*1000);
      //1ms wait

        *selvol=read_adc_ave(ADC_IMEAS,0,10000);

      delay_timer(1*1000);
      //1ms wait
      set_pps_resource(PPS_PMU_SENSE_CTRL,PPS_LOCAL_SENSE);

    set_pps_resource(PPS_PMU_IRNG,PPS_50mA_RNG);
    //PMU 50mA Setting
    set_pps_resource(PPS_PMU_ILIMIT,50*1000*1000);
    //PMU ILIMIT = 50mA



    }

    if((monitor_mode & CRY_CLK) !=0){
            // --- CRY CLK mode Out ---//
      sprintf(outbuf,"CRY CLK CLEAR");
      DataOut(Ffpt,outbuf);
      add_vhh_mask( lb3_pin );
      run_apg(_RAM_BOOT_RELAY);
    }


        // ************************* RAMBoot End Manage ***********************************

      run_apg(_RAM_BOOT_MONITOR_END);
      // RAM Boot End(APG)

//    load_vlf_offset(_SUB_MODEENTRY_RAM,1 ,4);   //ModeEntry Wait back
//    load_vlf_offset(_SUB_MODEENTRY_RAM,30,1200);//ModeEntry Wait back

    cpuerr = check_pin_errors( bistpoll_pins, 4 );
    // Boot����Error�o�͂�APG�p�^�����璊�o(DPASSDEND_CP�̔�r����)
    Cputotal = (bentime()-start_time-init_bentime())/1000;
    // Get Test Total Time

// ****************************************************************************
// DAXS Read
// ****************************************************************************

  set_strobe_mask(daxs_datao_pin);
  SetTimming_NS( daxs_trans.read_rate );
  select_vector_mode(poll_pins,_PE_APG_MODE);
  reconnect_pin(poll_pins);

    // ******* PowerUp ********

  if(VccSlow(daxs_trans.vcc,vcc[0])){
    return(HWFAIL);
  }
  PmuSlow(daxs_trans.vcc,vcc[0]);
    // ******* APG SetUp(Power) ********
  tempo1=0;
  if((vcc[1] != 0) && (vcc[2] != 0)){
    tempo1 = tempo1 + 0x01;
    //ext_vref ON
    sprintf(outbuf," Ext_Vref  ON  ");
    DataOut(Ffpt,outbuf);
  }else{
    sprintf(outbuf," Ext_Vref  OFF ");
    DataOut(Ffpt,outbuf);
  }

  load_vlf_offset(_SUB_MODEENTRY_DAXS,4,tempo1);

  SetVohVolVtt( daxs_trans.voh, daxs_trans.vol, daxs_trans.vtt, daxs_datao_pin );
  //�I�[��R�⃍�W�J��Pin��H/L����̓d���ݒ�(DAXS�]���p)

    // ******* Read RAM data ********

  for( cnt=RAM_TOP; cnt<=RAM_END; cnt++ ){
      WriteEcrMode8( cnt, 0xFF, SIZE_B );
  }

  result = RAMRunApg( 2, 0x2A00, OUTPUTIF_END );
  // DAXS transport 0=write command

  if((ReadEcrMode8(0x3D00,SIZE_B)==0xAA) ){
      printf("WT mode Test FAIL!!!");
  }else if((ReadEcrMode8(0x3D00,SIZE_B)==0x55) ){
      printf("WT mode Test PASS!!!");
  }else if((ReadEcrMode8(0x3D00,SIZE_B)==0x78) ){
      printf("WT mode Test Time Limit!!!");
  }else{
      printf("WT mode Test ECR data ERROR!!!");
      DispEcrBmData(0x3D00 , 0x00FF, DISP_ECR|DISP_1 );
	  result = FAIL;
  }

// ****************************************************************************
// EndManage
// ****************************************************************************

    // ******* get data ********
    //ECR => param
  for(cnt=IN_LWORDEND+1;cnt<OUT_BYTEEND;cnt++){
    (param + cnt) -> value = ReadEcrMode8((param + cnt) -> addr,(param + cnt) -> size);
  }
  for(cnt=OUT_BYTEEND+1;cnt<OUT_LWORDEND;cnt++){
    (param + cnt) -> value = ReadEcrMode8((param + cnt) -> addr,(param + cnt) -> size);
  }
  return(result);
}

