  int i,min_vol,max_vol,delta,center;
  int flg,tempo1;
  // ** CPU drive recklessly flg **
  int result;
  // Test Result
  int selmode,pmu_range,bm_data,ecr_data;
  char mat_value[100];
  int start_time;
  // Start Time For bentime
  int vs0,vs1,vs2;
  // Power bak
  int old_reg,end_flag;
  char mat_str[20];
  char disp_addres[256];

  DeviceSpecificPowerUp();

  flg = 0;
  selmode=GetValue(IN_TESTSEL,param);

  DispAddres(param,"",disp_addres);

  for( cnt=RAM_TOP; cnt<=RAM_END; cnt=cnt+4 ){
      WriteBmMode8( cnt, 0xFFFFFFFF, SIZE_L );
      WriteEcrMode8( cnt, 0xFFFFFFFF, SIZE_L );
  }

  connect_ps(PPS_CON_VNN1,PPS_CMODE_DISCONNECT);

    //PMU-Init
  set_pmu_range(UA250);
  set_vlimit(0);
    //set_ilimit(250*1000);
  set_ilimit(0);

// ******* BGR Code Check ********
  BGR_REG_CHECK(vcc[0],param);

    // ****** GET PARAMETER ******
  speed=GetValue(IN_EXTAL1,param);

  if(GetValue(IN_BDATA15,param) == 0)pmu_range = UA250;
  else pmu_range = GetValue(IN_BDATA15,param);

    // ****** DISP TAITOL ******
    //Vref��VrefH�̋L�q�ɕύX�K�v�H
  sprintf(outbuf,"TEST:%d [ %s ] vcc=%dmV ext_Vrefh=%dmV ext_Vref=%dmV F=%2dns PLL=%d(X%d) ", test++,mess,vcc[0],vcc[1],vcc[2],speed,GetValue(IN_PLLON,param),GetValue(IN_PLL_MULT,param));
  DataOut(Ffpt,outbuf);
  sprintf(outbuf,"Module:%s%s", DispMatName(mat_str,param),disp_addres);
  DataOut(Ffpt,outbuf);
    //Ldata�̌����ɕύX����K�v�L
  sprintf(outbuf,"BDATA00:%08X, LDATA0:%08X" ,GetValue(IN_BDATA00,param),GetValue(IN_LDATA0,param));
  DataOut(Ffpt,outbuf);

    // ****** SETUP ECR/BM ******
  Ecrsetup8(ECR_OVERL);

    // ******* RATE SetUp ********
  SetTimming_NS( daxs_trans.write_rate );

    // ******* PowerUp ********
  vs0=vcc[0];
  vs1=vcc[1];
  vs2=vcc[2];

  vcc[0]=daxs_trans.vcc;
    //vcc[1]=daxs_trans.vrefh;
    //vcc[2]=daxs_trans.vref;

    // ******* APG SetUp(Power) ********
  tempo1=0;
  if((vcc[1] != 0) && (vcc[2] != 0)){
    tempo1 = tempo1 + 0x01;
    //ext_vref ON
    sprintf(outbuf," Ext_Vref  ON  ");
    DataOut(Ffpt,outbuf);
  }else{
    sprintf(outbuf," Ext_Vref  OFF ");
    DataOut(Ffpt,outbuf);
  }

  load_vlf_offset(_SUB_MODEENTRY_DAXS,4,tempo1);

  if(SelectPowerSupply(mode,vcc)) {
  //�e�d���̋�����Level�̐ݒ�(DAXS�]���p)
    vcc[0]=vs0;
    vcc[1]=vs1;
    vcc[2]=vs2;
    return(HWFAIL);
  }
  SetVohVolVtt( daxs_trans.voh, daxs_trans.vol, daxs_trans.vtt, daxs_datao_pin );
  //�I�[��R�⃍�W�J��Pin��H/L����̓d���ݒ�(DAXS�]���p)
  vcc[0]=vs0;
  vcc[1]=vs1;
  vcc[2]=vs2;

// ****************************************************************************
// Write BM
// ****************************************************************************

    // ****** MAKE ASM PATH ******
  strcpy( binpat, glob_cdp ); strcat( binpat, glob_binpat_at );
  strcat( binpat, pat );

  patsize = CheckPatLength(binpat) - PAT_FILE_HEADER_SIZE;

    // ******* FILE BM WRITE *********
  datasize = comp_load_bm (binpat);
  // comp_load_bm:file pattern => BM


  if(FAIL==datasize) {
  // path/fail check
    sprintf(outbuf," !!! NOT OPEN FILE PATH -> %s (checksum:H'%X) !!!",binpat,datasize);
    DataOut(Ffpt,outbuf);
    DeviceLevelsPowerDown();
    return(NOPATFAIL);
  }else{
    sprintf(outbuf," LOAD FILE PATH -> %s (checksum:H'%X)",binpat,datasize);
    DataOut(Ffpt,outbuf);
  }


    // ******* Parameter BM Write ********
  result = ParamTransBM(param);

  WriteBmMode8( 0x3C00 , 0x00100000, SIZE_L );
  // Dummy Data 18/04/11 Aoki

    // ** Trans Check **
  if(PASS!=result){
    sprintf(outbuf,"  TRANS ERROR!!  (param => BM) ");
    DataOut(Ffpt,outbuf);
    return(RAMFAIL);
  }else{
    sprintf(outbuf,"  TRANS CHECK OK (param => BM) ");
    DataOut(Ffpt,outbuf);
  }


  ParamConditionDisp(PDALL,0,param);
  //���͗pIF�̏o��

// ****************************************************************************
// DAXS Transport
// ****************************************************************************
    // ******* Start tests ********
    sprintf(outbuf,"Write RAM ");
    DataOut(Ffpt,outbuf);

    result = RAMRunApg( 0, RAM_TOP, OUTPUTIF_END );
    // DAXS transport 0=write command

  if(PASS!=result){
    return(RAMFAIL);
  }


    sprintf(outbuf,"Read RAM ");
    DataOut(Ffpt,outbuf);

  SetTimming_NS( daxs_trans.read_rate );

  set_strobe_mask(daxs_datao_pin);
  //Compare Setting command

    result = RAMRunApg( 2, RAM_TOP, OUTPUTIF_END );
    // DAXS transport 0=write command

  for(i=RAM_TOP;i<=OUTPUTIF_END;i=i+4){
    bm_data=ReadBmMode8(i,SIZE_L);
    ecr_data=ReadEcrMode8(i,SIZE_L);
    if(bm_data!=ecr_data){
      printf("BM <=> ECR Comp ERROR!!! Addr = %X, BM = %X, ECR = %X ",i,bm_data,ecr_data);
      result = FAIL;
    }
  }


  if(PASS!=result){
    return(RAMFAIL);
  }

  sprintf(outbuf," <<<<< EXTRAM transfer OK >>>>>");
  DataOut(Ffpt,outbuf);
  //CommentOut for RAMBOOT Check

// ****************************************************************************
// DAXS RAMBOOT
// ****************************************************************************
    // ** Power Change **
  if(VccSlow(vcc[0],daxs_trans.vcc)){
    return(HWFAIL);
  }

    // ** Comp Pin SetUp **
  set_strobe_mask(bistpoll_pins);
  // ��rPin�̐ݒ�(RAMBoot�����܂ł̑ҋ@���ԂɎg�p)
  select_vector_mode(poll_pins,_PE_VECTOR_MODE);
  //180314 Add-morioka For RamBoot
  reconnect_pin(poll_pins);
  //180314 Add-morioka For RamBoot

    // ** Test Speed SetUp **
  SetTimming_NS(speed);
  ChangeTimming_GTSLTS( EXTCYLJ, 1, MODEENTRY_SPEED );
  // ModeEntry���g���ݒ� GTS=1,20MHz

    // ******* APG SetUp(Power) ********
  tempo1=0;
  if((vcc[1] != 0) && (vcc[2] != 0)){
    tempo1 = tempo1 + 0x01;
    //ext_vref ON
    sprintf(outbuf," Ext_Vref  ON  ");
    DataOut(Ffpt,outbuf);
  }else{
    sprintf(outbuf," Ext_Vref  OFF ");
    DataOut(Ffpt,outbuf);
  }

    // ******* APG SetUp(Wait) ********
