  // 1us Wait
  load_vlf_offset(_SUB_MODEENTRY_RAM,1,300000/2/MODEENTRY_SPEED);
  // 300us Wait
  load_vlf_offset(_SUB_MODEENTRY_RAM,2, 70000/MODEENTRY_SPEED);
  // 70ms Wait
  load_vlf_offset(_SUB_MODEENTRY_RAM,3,tempo1);
  // Vdd/Vddh On/Off
  load_vlf_offset(_SUB_RAMBT_END,0,500*waittime/speed);
  // RAMBootEnd Wait = waittime x(500x200x2000ns)
  load_vlf_offset(_SUB_RAMBT_POLL,0,500*waittime/speed);
  // RAMBootPoll Wait = waittime x(500x200x200ns)


  SetVohVolVtt( 10*vcc[0]/100, 10*vcc[0]/100, 5*vcc[0]/10 , bistpoll_pins );
  //�I�[��R�⃍�W�J��Pin��H/L����̓d���ݒ�(DAXS�]���p)

    // ************** PMU Setting *******************

  sprintf(outbuf,"  PMU Set");
  DataOut(Ffpt,outbuf);

  if(mode & MONITOR_MODE){
    switch(selmode){
      case MONITOR_VRSG:
      case MONITOR_VHH_E:
      case MONITOR_VHH_P:
                //set_vlimit(3300);      // PMU���Ȃ��Ȃ���Ԃ�PMU��3.3V�d���ɂ��Ă���
		//set_ilimit(250*1000);
		//delay_timer(100);
	set_ilimit(0);
        set_vlimit(0);
	connect_ps(PPS_CON_VNN1,PPS_CMODE_PMU);
        break;
      default:
      // Default Error
        DeviceLevelsPowerDown();
        printf("MONITOR_MODE PMU setting, Code ERROR!!! code=%X",selmode);
        //Define Error, Check selmode value return(FAIL);
        break;
    }

  }else if(mode & APPLY_MODE){
    switch(selmode){
      case AUTOTRIM_VRSG:


      break;
      case AUTOTRIM_BGR08:
        set_vlimit(0);
	connect_ps(PPS_CON_VNN1,PPS_CMODE_PMU);
        set_pmu_range(UA250);
        set_ilimit(250*1000);
      break;
    }
  }

    // ************************** Run APG & Monitor(Apply) *****************************
    start_time = bentime();
    // Get Test Start Time
    sprintf(outbuf,"  APG Start");
    DataOut(Ffpt,outbuf);

    if(mode & MONITOR_MODE){
      switch(selmode){
        case MONITOR_VRSG:
        case MONITOR_VHH_E:
        case MONITOR_VHH_P:
          comp_set_ilimit(0);
                    //load_vlf_offset(_SUB_RAMBT_POLL,0,2000/speed);    // 80ms fix(2000*200*200ns)
          run_apg(_RAM_BOOT_MONITOR_CTRL);
		  delay_timer(5*1000);
		  // 5ms Wait
          SITE_MASK (1, read_pmu_status(0x20));
          // V measurement
          SITE_MASK (1, *selvol=read_adc_ave(ADC_VMEAS,0,100));
          break;

        default:
          DeviceLevelsPowerDown();
          printf("MONITOR_MODE Run APG, Code ERROR!!! code=%X",selmode);
          //Define Error, Check selmode value return(FAIL);
          break;
      }
    }else if(mode & APPLY_MODE){
    switch(selmode){
      case AUTOTRIM_VRSG:
  load_vlf_offset(_SUB_RAMBT_POLL,0,2);
  // RAMBootPoll Wait = waittime x(500x200x200ns)
          run_apg(_RAM_BOOT_CTRL);





      break;
      case AUTOTRIM_BGR08:
        if(GetValue(IN_BDATA00,param) == 0){

          load_vlf_offset(_SUB_RAMBT_POLL,0,2);
          // RAMBootPoll Wait = waittime x(500x200x200ns)
          set_vlimit(*selvol);
	  run_apg(_RAM_BOOT_CTRL);
        }else if(GetValue(IN_BDATA00,param) == 1){
          load_vlf_offset(_SUB_RAMBT_POLL,0,1000*waittime/speed);
          // RAMBootPoll Wait = waittime x(500x200x200ns)
          set_vlimit(3800);
          // 3.8V���VrsgMaxOver���
	  run_apg(_RAM_BOOT_MONITOR_CTRL);
          load_vlf_offset(_SUB_RAMBT_DEND_POLL,0,1000*(waittime+4)/speed);
          // RAMBootPoll Wait = waittime x(500x200x200ns)

	  while(end_flag != 1){
	    set_vlimit(*selvol);
	    run_apg(_RAM_BOOT_DEND_POLL);

	    if(1 == check_pin_errors( bistpoll_pins, 4 )){
	      end_flag = 1;
	    }else{
	      *selvol = *selvol - 2;
	    }
		if(*selvol <= 3000){
		  end_flag = 1;
          DeviceLevelsPowerDown();
          //�e�d��OFF�R�}���h
          DeviceSpecificPowerDown();
		  return(FAIL);

		}

	  }
	}
      break;
        default:
          DeviceLevelsPowerDown();
          printf("MONITOR_MODE Run APG, Code ERROR!!! code=%X",selmode);
          //Define Error, Check selmode value return(FAIL);
          break;
      }


    }else{
      printf("Mode Select Error!!! mode=%X",mode);
      return(FAIL);
    }

        // ************************* RAMBoot End Manage ***********************************

    if(mode & MONITOR_MODE){
            //load_vlf_offset(_SUB_RAMBT_END,1,1000); // 50*cycle
      load_vlf_offset(_SUB_RAMBT_END,0,500*waittime/speed);
      // RAMBootEnd Wait = waittime x(500x200x2000ns)
      run_apg(_RAM_BOOT_MONITOR_END);
      // RAM Boot End(APG)
    }

	connect_ps(PPS_CON_VNN1,PPS_CMODE_DISCONNECT);
    set_vlimit(0);
    // PMU 0V
    reconnect_pin(v5_pin);
    // PMU reconnect PNN
    set_invert_mask(no_pin);
    // �K�v�����H

    cpuerr = check_pin_errors( bistpoll_pins, 4 );
    // Boot����Error�o�͂�APG�p�^�����璊�o(DPASSDEND_CP�̔�r����)
    Cputotal = (bentime()-start_time-init_bentime())/1000;
    // Get Test Total Time

// ****************************************************************************
// DAXS Read
// ****************************************************************************

  set_strobe_mask(daxs_datao_pin);
  SetTimming_NS( daxs_trans.read_rate );
  select_vector_mode(poll_pins,_PE_APG_MODE);
  reconnect_pin(poll_pins);

    // ******* PowerUp ********

  if(VccSlow(daxs_trans.vcc,vcc[0])){
    return(HWFAIL);
  }

    // ******* APG SetUp(Power) ********
  tempo1=0;
  if((vcc[1] != 0) && (vcc[2] != 0)){
    tempo1 = tempo1 + 0x01;
    //ext_vref ON
    sprintf(outbuf," Ext_Vref  ON  ");
    DataOut(Ffpt,outbuf);
  }else{
    sprintf(outbuf," Ext_Vref  OFF ");
    DataOut(Ffpt,outbuf);
  }

  load_vlf_offset(_SUB_MODEENTRY_DAXS,4,tempo1);

  SetVohVolVtt( daxs_trans.voh, daxs_trans.vol, daxs_trans.vtt, daxs_datao_pin );
  //�I�[��R�⃍�W�J��Pin��H/L����̓d���ݒ�(DAXS�]���p)

    // ******* Read RAM data ********

  for( cnt=0x2A00; cnt<=OUTPUTIF_END; cnt=cnt+4 ){
      WriteEcrMode8( cnt, 0xFFFFFFFF, SIZE_L );
  }

  result = RAMRunApg( 2, 0x2A00, OUTPUTIF_END );
  // DAXS transport 0=write command

  DeviceLevelsPowerDown();
  //�e�d��OFF�R�}���h
  DeviceSpecificPowerDown();


  if((ReadEcrMode8(0x3D00,SIZE_B)==0xAA) &&
     (ReadEcrMode8(0x3D01,SIZE_B)==0xAA) &&
     (ReadEcrMode8(0x3D02,SIZE_B)==0xAA) &&
     (ReadEcrMode8(0x3D03,SIZE_B)==0xAA) ){
      printf("WT mode Test FAIL!!!");
  }else if((ReadEcrMode8(0x3D00,SIZE_B)==0x55) &&
           (ReadEcrMode8(0x3D01,SIZE_B)==0x55) &&
           (ReadEcrMode8(0x3D02,SIZE_B)==0x55) &&
           (ReadEcrMode8(0x3D03,SIZE_B)==0x55) ){
      printf("WT mode Test PASS!!!");
  }else{
      printf("WT mode Test ECR data ERROR!!!");
      DispEcrBmData(0x3D00 , 0x00FF, DISP_ECR|DISP_1 );
      return(FAIL);
  }


// ****************************************************************************
// EndManage
// ****************************************************************************

    // ******* get data ********
    //ECR => param
  for(cnt=IN_LWORDEND+1;cnt<OUT_BYTEEND;cnt++){
    (param + cnt) -> value = ReadEcrMode8((param + cnt) -> addr,(param + cnt) -> size);
  }
  for(cnt=OUT_BYTEEND+1;cnt<OUT_LWORDEND;cnt++){
    (param + cnt) -> value = ReadEcrMode8((param + cnt) -> addr,(param + cnt) -> size);
  }
  CpuModeOutput(mode,param);

  if(cpuerr == 1) {
    switch(GetValue(OUT_JUDGE1,param)) {
      case CPASS:
        sprintf(outbuf,"** PASS ** Cpu Total=%dms",Cputotal);
        DataOut(Ffpt,outbuf);
        break;
      case CFAIL:
        sprintf(outbuf,"-- FAIL -- Cpu total=%dms",Cputotal);
        DataOut(Ffpt,outbuf);
        break;
      case CFLAG:
        sprintf(outbuf,"-- FLAG_FAIL -- Cpu Total=%dms",Cputotal);
        DataOut(Ffpt,outbuf);
        break;
      case READFAIL:
        sprintf(outbuf,"-- READ_FAIL -- Cpu Total=%dms",Cputotal);
        DataOut(Ffpt,outbuf);
        break;
      default:
        sprintf(outbuf,"-- FAIL -- None (%04X) %dms",((0x00FF&GetValue(OUT_JUDGE1,param))<<8)|((0xFF00&GetValue(OUT_JUDGE1,param))>>8),Cputotal);
        DataOut(Ffpt,outbuf);
        break;
    }
  }else{
    sprintf(outbuf,"-- FAIL -- !!! TimeOver !!! total=%dms",Cputotal);
    DataOut(Ffpt,outbuf);
        //return(FAIL);
  }

    // ******* Monitor Result ********

  if(mode & MONITOR_MODE){
    switch(mode & 0x0000FFFF){
      case  MVSSMON:
      case  MVSSMON_CH:
      case  MVSSMON_20K:
        sprintf(outbuf,"  Monitor Result VSSMON = %dmV",*selvol);
        DataOut(Ffpt,outbuf);
        break;
      case  MVCCMON:
        sprintf(outbuf,"  Monitor Result VCCMON = %dmV",*selvol);
        DataOut(Ffpt,outbuf);
        break;
      case  MVRSGMON:
        sprintf(outbuf,"  Monitor Result VRSGMON = %dmV",*selvol);
        DataOut(Ffpt,outbuf);
        break;
      default:
        printf("Result Setting Error!! mode code = %X",mode);
        return(FAIL);
        break;
      }
    selvol = center;
    }else{
      sprintf(outbuf," AutoTrim JUDGE = 0x%04X",((0x00FF&GetValue(OUT_JUDGE1,param))<<8)|((0xFF00&GetValue(OUT_JUDGE1,param))>>8));
      DataOut(Ffpt,outbuf);
    }
  return(PASS);
}

