void SwapBMData4byte(int start_addr,int end_addr)
{
  int addr;
  int buf;

  addr = start_addr;
  while( addr <= end_addr ){
    buf = (((read_bm(addr+3)<<24)&0xff000000) |
           ((read_bm(addr+2)<<16)&0x00ff0000) |
           ((read_bm(addr+1)<<8)&0x0000ff00) |
            (read_bm(addr)&0x000000ff));
    comp_write_bm(addr,buf>>24);
    comp_write_bm(addr+1,buf>>16);
    comp_write_bm(addr+2,buf>>8);
    comp_write_bm(addr+3,buf);

    addr += 4;
  }
}

void SwapECRData4byte(int start_addr,int end_addr)
{
  int addr;
  int buf;

  addr = start_addr;
  while( addr <= end_addr ){
    buf = (((read_ecr(addr+3)<<24)&0xff000000) |
           ((read_ecr(addr+2)<<16)&0x00ff0000) |
           ((read_ecr(addr+1)<<8)&0x0000ff00) |
            (read_ecr(addr)&0x000000ff));

    write_ecr(addr,buf>>24);
    write_ecr(addr+1,buf>>16);
    write_ecr(addr+2,buf>>8);
    write_ecr(addr+3,buf);

    addr += 4;
  }
}

int ParamTransBM(interface_t* param )
{
  int cnt,param_data, bm_data;

    // ******* Parameter BM Write ********
  for(cnt=0;cnt<IN_BYTEEND;cnt++){
  // write register(byte) data
    WriteBmMode8((param + cnt) -> addr,(param + cnt) -> value,(param + cnt) -> size);
  }
  for(cnt=IN_BYTEEND+1;cnt<IN_LWORDEND;cnt++){
  // write other data
    WriteBmMode8((param + cnt) -> addr,(param + cnt) -> value,(param + cnt) -> size);
  }
  for(cnt=OUTPUTIF_TOP;cnt<OUTPUTIF_END;cnt+=4){
  // write dummy data
    WriteBmMode8(cnt,0xFFFFFFFF,SIZE_L);
  }


    //WriteBmMode8((param + OUT_JUDGE) -> addr,CHECK_CODE,(param + OUT_JUDGE) -> size);    // Write CheckCode

    // *** Comp parameter <=> BM ***
  for(cnt=0;cnt<IN_BYTEEND;cnt++){
  // Comp register(byte) data
    param_data = ((param + cnt) -> value);
    bm_data    = ReadBmMode8((param + cnt) -> addr,(param + cnt) -> size);
    if( param_data != bm_data ){
      sprintf(outbuf,"  TRANS ERROR1!!(param => BM) addr=H'%X data: H'%X(param)<=>H'%X(BM)", (param + cnt) -> addr,param_data, bm_data);
      DataOut(Ffpt,outbuf);
      return(FAIL);
    }
  }
  for(cnt=IN_BYTEEND+1;cnt<IN_LWORDEND;cnt++){
  // comp other data
    param_data = ((param + cnt) -> value);
    bm_data    = ReadBmMode8((param + cnt) -> addr,(param + cnt) -> size);
    if( param_data != bm_data ){
      sprintf(outbuf,"  TRANS ERROR2!!(param => BM) addr=H'%X data: H'%X(param)<=>H'%X(BM)", (param + cnt) -> addr,param_data, bm_data);
      DataOut(Ffpt,outbuf);
      return(FAIL);
    }
  }
  for(cnt=OUTPUTIF_TOP;cnt<OUTPUTIF_END;cnt+=4){
  // comp dummy data
    param_data = 0xFFFFFFFF;
    bm_data    = ReadBmMode8(cnt,SIZE_L);
    if( param_data != bm_data ){
      sprintf(outbuf,"  TRANS ERROR3!!(param => BM) addr=H'%X data: H'%X(param)<=>H'%X(BM)", (param + cnt) -> addr,param_data, bm_data);
      DataOut(Ffpt,outbuf);
      return(FAIL);
    }
  }
  return(PASS);
}

int VthReadSearch(int judge, int vcc[NUM_POWERSUPPLY],interface_t* param,int waittime,int delta)
{
  int selvol,start_vol,end_vol,delta_vol,expect,step,mode;
  char file_name;
  int result,i,k;
  int tempo1,bdata00_bak,bdata01_bak,speed,testsel_bak;

  printf("judge = %d",judge);


  result = 0;
  i = 0;
  start_vol = end_vol = 0;
  selvol = 0;

    //-- Initial Setting --//
  bdata00_bak = GetValue(IN_BDATA00,param);
    //SetValue(IN_BDATA16,param,VTHREAD_EDGE);

  if(judge == 0){
  // - => +
    bdata01_bak = SetValue(IN_BDATA01,param,0x00);
    //All"0" judge
    delta_vol =   delta*1;
    //Step : +0.5V
    start_vol =   0;
    //start level : -2.00V
    end_vol   =  2000;
    //end level : 1.25V
    expect    =  0x00;
    //OUT_JUDGE�̊��Ғl

  }else if(judge == 1){
  // + => -
    bdata01_bak = SetValue(IN_BDATA01,param,0x01);
    //All"1" judge
    delta_vol =  delta*-1;
    //Step : +0.5V
    start_vol =  0;
    //start level : 1.25V
    end_vol   = -2000;
    //end level: -2.00V
    expect    =  0x01;
    //OUT_JUDGE�̊��Ғl

  }else{
  // Error
    printf("judge number Error!!! judge = %d",judge);
    return(FAIL);
  }

    // param Set 
  speed = SetValue(IN_EXTAL1,param,500);
  //2MHz CLK SET
  testsel_bak = SetValue(IN_TESTSEL,param,expect);



  for (k = 1; k <= 1; k++){


    switch(k){
      case 1 :
        printf(" 1st Step VthRead Start ");
        break;

      case 2 :
      // 0.1V step
        printf(" 2nd Step VthRead Start ");
        start_vol = selvol - delta_vol;
	end_vol   = selvol;
	delta_vol = delta_vol / 5;
        break;

      case 3 :
      // 0.02V(20mV) step
        printf(" 3rd Step VthRead Start ");
        start_vol = selvol - delta_vol;
	end_vol   = selvol;
	delta_vol = delta_vol / 5;
        break;
    }

    step = ((end_vol - start_vol) / delta_vol) + 1;
    printf("Start =%dmV, End = %dmV, Step = %dmV",start_vol,end_vol,delta_vol);
    for (i = 0; i <= step; i++){
      selvol = start_vol + i * delta_vol;
	  	  //printf("enter selvol ->");DigitInput(&selvol);

      if(selvol <=-3500){
        printf("VthRead level Error!!! level = %dmV",selvol);
        return(FAIL);
      }else if(selvol <= -2000){
        SetValue(IN_BDATA00,param,0x01);
        //Select Vth-Read1
        printf("Caution! VthRead1 level < -2.0V , level = %dmV",selvol);
	mode = VSSMON_APP;
      }else if(selvol <= 0){
        SetValue(IN_BDATA00,param,0x01);
        //Select Vth-Read1
        mode = VSSMON_APP;
      }else if(selvol <= 1250 ){
        SetValue(IN_BDATA00,param,0x02);
        //Select Vth-Read2    
        mode = VSSMON_APP;
      }else if(selvol <= 3300 ){
        SetValue(IN_BDATA00,param,0x03);
        //Select Vth-Read3    
        mode = VCCMON_APP;
      }else{
        printf("VthRead level Error!!! level = %dmV",selvol);
        return(FAIL);
      }
      printf("Vth-Read Start level = %dmV",selvol);
	  SetValue(OUT_JUDGE1,param,0);
      result = CpuModeMonitor(mode, vcc, param,waittime,CreatePatFileName("readall_code_at"),"CPU READ VthSearch", selvol);
      // Vth-Read ���s

      if(result != PASS){
        sprintf(outbuf,"Vth-Read Fail!! CpuModeMonitor-Error!!!");
	DataOut(Ffpt,outbuf);
	return(result);
      }

      if(READFAIL == GetValue(OUT_JUDGE1,param)){
        break;
        // "i" Loop break -> next "k"
      }

    }
        // param Return 
  }
  SetValue(IN_EXTAL1,param,speed);
  SetValue(IN_TESTSEL,param,testsel_bak);

  return(selvol);
}

