    if ( GetValue(IN_BDATA01,param) == 0) sprintf(pat_name,"readcount_code_at");
    else                                  sprintf(pat_name,"readstripecount_code_at");
  }
  result = 0; test_item = 0;
  i = 0;
  printf("speed = %d",GetValue(IN_EXTAL1,param));
  switch (vth_mode){
    case 1:
      mode = VSSMON_APP;
      //Connect PMU <=> VSSMON
      max_vol =  0;
      //max = 0V
      break;
    case 2:
      mode = VSSMON_APP;
      //Connect PMU <=> VSSMON
      max_vol = 1250;
      //max = 1.25V
      break;
    case 3:
      mode = VCCMON_APP;
      //Connect PMU <=> VCCMON
      max_vol = vcc[0];
      //max = Vcc
      break;
    case 12:
      vth_mode = 1;
      //Start Mode = 1
      test_item = 12;
      mode = VSSMON_APP;
      //Connect PMU <=> VSSMON
      max_vol = 1250;
      //max = 2.5V
      break;
    case 23:
      vth_mode = 2;
      //Start Mode = 2
      test_item = 23;
      mode = VSSMON_APP;
      //Connect PMU <=> VSSMON
      max_vol = 2500;
      //max = 2.5V
      break;
    default:
      printf("vth_mode Select Error!!! vth_mode = %X",vth_mode);
      return(FAIL);
      break;
  }

  printf("vth_mode = %d, min_vol = %d, File name = %s",vth_mode,min_vol,file_name);

  bdata00_bak = SetValue(IN_BDATA00,param,vth_mode);
  // VthRead num select

  start_time = bentime();
  // Get Test Start Time

  for (selvol = min_vol; selvol <= max_vol; selvol = selvol + delta_vol){
  //Vth-Read Loop min_vol~max_bit Hit(max_vol)

    if ( test_item == 12 ) {
      if ( ( selvol > 0 ) && ( vth_mode !=2 ) ) {
        vth_mode = 2;
        SetValue(IN_BDATA00,param,vth_mode);
        // VthRead num select  
		inif_flag = 1;
      }
    }

    if ( test_item == 23 ) {
      if ( ( selvol > 1200 ) && ( vth_mode !=3 ) ) {
        vth_mode = 3;
        mode = VCCMON_APP;
        //Connect PMU <=> VCCMON
        SetValue(IN_BDATA00,param,vth_mode);
        // VthRead num select
	inif_flag = 1;
      }
    }

    printf("VthRead%d Vol = %d , Start",vth_mode,selvol);

    if(first_flag==1){
    // Initial mode
      first_flag = 0;
	  inif_flag = 0;

      repeat_mode = INITIAL_SET | OUTIF_READ;
    }else{
    // Normal Mode
      repeat_mode = OUTIF_READ;
    }

    if(inif_flag ==1){
      inif_flag = 0;
      repeat_mode = repeat_mode | INIF_SET | RAMBOOT_CHANGE;
      //����IF�ύXMode�ǉ�
    }

        //result = CpuModeMonitor(mode, vcc, param,waittime,CreatePatFileName(pat_name),"CPU READ VthRead", &selvol); // Vth-Read ���s
