    // --------------------------------------------------------------------------
  int i, cnt, cpuerr, datasize, patsize, vs0, vs1, vs2, speed, temp,vtemp[NUM_POWERSUPPLY];
  int result, start_time,old_reg,tempo1,tempo2,bm_data,ecr_data, pf_flag;
  char mat_str[20];
