  DeviceSpecificPowerUp();
    // Initialyze
  pf_flag = cnt = cpuerr = datasize = patsize = vs0 = vs1 = vs2 = speed = tempo1 = 0;
  DispAddres(param,"",disp_addres);

  for( cnt=RAM_TOP; cnt<=RAM_END; cnt=cnt+4 ){
            //WriteBmMode8( cnt, 0xFFFFFFFF, SIZE_L );
      WriteEcrMode8( cnt, 0xFFFFFFFF, SIZE_L );
  }

    //speed=GetValue(IN_EXTAL1,param);
    //speed=GetValue(IN_EXTAL1,param);
  speed=GetValue(IN_EXTAL_PS,param);

    // ****** DISP TAITOL ******
    //Vref��VrefH�̋L�q�ɕύX�K�v�H
  sprintf(outbuf,"TEST:%d [ %s ] vcc=%dmV ext_Vrefh=%dmV ext_Vref=%dmV F=%2dps PLL=%d(X%d) ", test++,mess,vcc[0],vcc[1],vcc[2],speed,GetValue(IN_PLLON,param),GetValue(IN_PLL_MULT,param)); DataOut(Ffpt,outbuf);
  sprintf(outbuf,"Module:%s%s", DispMatName(mat_str,param),disp_addres); DataOut(Ffpt,outbuf);
    //Ldata�̌����ɕύX����K�v�L
  sprintf(outbuf,"BDATA00:%08X, LDATA0:%08X", GetValue(IN_BDATA00,param),GetValue(IN_LDATA0,param)); DataOut(Ffpt,outbuf);
  if( CheckFK(FK_DISP_DEBUG) ){ for( i=0; i<16; i++ ){ if( in_ldata[ i ]!=0x55345678 ){ sprintf( outbuf,"in_ldata[%d]=%08X, ", i, in_ldata[ i ] ); DataOut(Ffpt,outbuf); } } DataOut(Ffpt,""); }
  // ****** SETUP ECR/BM ******

  if( NULL!=strstr( mess, "UserBoot" ) ) goto DAXS_RAMBOOT;

    // ******* RATE SetUp ********
  SetTimming_NS( daxs_trans.write_rate );

    // ******* PowerUp ********
  vs0=vcc[0]; vs1=vcc[1]; vs2=vcc[2];
  vcc[0]=daxs_trans.vcc;
  vcc[1]=daxs_trans.vrefh;
  vcc[2]=daxs_trans.vref;

    // ******* APG SetUp(Power) ********
  tempo1=0;
  if((vcc[1] != 0) && (vcc[2] != 0)){
    tempo1 = tempo1 + 0x01;
    //ext_vref ON
    if( CheckFK(FK_DISP_DEBUG) ) DataOut(Ffpt," Ext_Vref  ON  \n");
  }else{
    if( CheckFK(FK_DISP_DEBUG) ) DataOut(Ffpt," Ext_Vref  OFF \n");
  }

  load_vlf_offset(_SUB_MODEENTRY_DAXS,4,tempo1);

  if(SelectPowerSupply(mode,vcc)) {
  //�e�d���̋�����Level�̐ݒ�(DAXS�]���p)
    vcc[0]=vs0;
    vcc[1]=vs1;
    vcc[2]=vs2;
    return(HWFAIL);
  }
  SetVohVolVtt( daxs_trans.voh, daxs_trans.vol, daxs_trans.vtt, daxs_datao_pin );
  //�I�[��R�⃍�W�J��Pin��H/L����̓d���ݒ�(DAXS�]���p)
  vcc[0]=vs0;
  vcc[1]=vs1;
  vcc[2]=vs2;

// ****************************************************************************
// Write BM
// ****************************************************************************

    // ****** MAKE ASM PATH ******
  strcpy( binpat, glob_cdp ); strcat( binpat, glob_binpat_logic );
  strcat( binpat, pat );
  patsize = CheckPatLength(binpat) - PAT_FILE_HEADER_SIZE;
  datasize = comp_load_bm (binpat);

  if(FAIL==datasize) {
  // path/fail check
    sprintf(outbuf," !!! NOT OPEN FILE PATH -> %s (checksum:H'%X) !!!",binpat,datasize); DataOut(Ffpt,outbuf); DeviceLevelsPowerDown();
    return(NOPATFAIL);
  }else{
    sprintf(outbuf," LOAD FILE PATH -> %s (checksum:H'%X)",binpat,datasize); DataOut(Ffpt,outbuf);
  }

    // input data bm set
  for( i = 0; i<16; i++ ){
    if( in_ldata[ i ] != 0x55345678 ) WriteBmMode8( 0x40 + i*4, in_ldata[ i ], SIZE_L );
  }



// ****************************************************************************
// DAXS Transport
// ****************************************************************************
    // ******* Start tests ********
    //printf("Write RAM ");               // Print Retry Count  RAMRunApg( 0, RAM_TOP, OUTPUTIF_END );   /* DAXS transport 0=write command */


    //printf("Read RAM ");                // Print Retry Count  SetTimming_NS( daxs_trans.read_rate );

  set_strobe_mask(daxs_datao_pin);
  //Compare Setting command

  result = RAMRunApg( 2, RAM_TOP, OUTPUTIF_END );
  // DAXS transport 2=ecr dump command

  for(i=RAM_TOP;i<=OUTPUTIF_END;i=i+4){
    bm_data=ReadBmMode8(i,SIZE_L);
    ecr_data=ReadEcrMode8(i,SIZE_L);
    if(bm_data!=ecr_data){
      sprintf( outbuf, "BM <=> ECR Comp ERROR!!! Addr = %X, BM = %X, ECR = %X ",i,bm_data,ecr_data ); DataOut(Ffpt,outbuf);
      result = FAIL;  break;
    }
  }
  if( CheckFK(FK_DISP_DEBUG) ){ DispEcrBmData(0x0 , 0x0100, DISP_BM|DISP_1 );  DispEcrBmData(0x3D00 , 0x0100, DISP_BM|DISP_1 ); }
  if(PASS!=result){
    return(RAMFAIL);
  }

  DataOut( Ffpt, " <<<<< EXTRAM transfer OK >>>>>\n" );
  //CommentOut for RAMBOOT Check

// ****************************************************************************
// DAXS RAMBOOT
// ****************************************************************************
DAXS_RAMBOOT:
    // ** Power Change **
  vs0 = vcc[0];
  vcc[0] = 3300;
  if(SelectPowerSupply(mode,vcc)) {
  //�e�d���̋�����Level�̐ݒ�(RAMBoot�]���p)
    return(HWFAIL);
  }

  if(VccSlow(vs0,vcc[0])){
    return(HWFAIL);
  }
  vcc[0] = vs0;

    // ** Comp Pin SetUp **
  set_strobe_mask(bistpoll_pins);
  // ��rPin�̐ݒ�(RAMBoot�����܂ł̑ҋ@���ԂɎg�p)
  select_vector_mode(poll_pins,_PE_VECTOR_MODE);
