  reconnect_pin(poll_pins);
  //180314 Add-morioka For RamBoot

    // ** Test Speed SetUp **
    //if( speed<=TM_SET_NS_MAX ){ SetTimming_NS(speed); }
    //else                      { SetTimming_PS(speed); speed = speed / 1000; }
    //SetTimming_PS(speed);
