    sprintf( outbuf,"ATBM1(DATAI) = %d[mV]  %d[nA]", tempo2, tempo1 ); DataOut( Ffpt, outbuf );
    reconnect_pin( daxs_datai_pin );
    connect_pmu( vcl1_pin );
    SITE_MASK( 1, tempo1 = read_pmu_status( 0x08 ) );
    SITE_MASK( 1, tempo2 = read_adc_ave( ADC_VMEAS, 0, 10 ) );
    SITE_MASK( 1, tempo1 = read_adc_ave( ADC_IMEAS, 0, 10 ) );
    sprintf( outbuf,"VCL1 = %d[mV]  %d[nA]", tempo2, tempo1 ); DataOut( Ffpt, outbuf );
    reconnect_pin( vcl1_pin );
    connect_pmu( vcl2_pin );
    SITE_MASK( 1, tempo1 = read_pmu_status( 0x08 ) );
    SITE_MASK( 1, tempo2 = read_adc_ave( ADC_VMEAS, 0, 10 ) );
    SITE_MASK( 1, tempo1 = read_adc_ave( ADC_IMEAS, 0, 10 ) );
    sprintf( outbuf,"VCL2 = %d[mV]  %d[nA]", tempo2, tempo1 ); DataOut( Ffpt, outbuf );
    reconnect_pin( vcl2_pin );
    run_apg (_RAM_BOOT_CTRL_RESL);
  }else if( NULL!=strstr( pat, "vbb_monitor") ){
    run_apg (_RAM_BOOT_CTRL_RESH);
    // Execute Test Pattern
    set_pmu_range( UA250 );
    // range NA2500, UA25, UA250, UA2500, MA25, MA250 MA1000
