    SITE_MASK( 1, tempo2 = read_adc_ave( ADC_IMEAS, 0, 10 ) );
    sprintf( outbuf,"VBB(VBN) = %d[mV]  %d[nA]", tempo1, tempo2 ); DataOut( Ffpt, outbuf );
    reconnect_pin( vbn_pin );
    run_apg (_RAM_BOOT_CTRL_RESL);
  }else if( NULL!=strstr( mess, "UserBoot" ) ){
    load_vlf_offset(_SUB_MODEENTRY_ROM,1,  1000/2/speed);
    // 1us Wait
    load_vlf_offset(_SUB_MODEENTRY_ROM,2,300000/2/speed);
    // 300us Wait
    load_vlf_offset(_SUB_MODEENTRY_ROM,3, 70000/speed);
    // 70ms Wait
    load_vlf_offset(_SUB_MODEENTRY_ROM,4,tempo1);
    // Vdd/Vddh On/Off
    run_apg ( _USER_BOOT_CTRL );
  }else{
    run_apg (_RAM_BOOT_CTRL);
    // Execute Test Pattern
  }
  Cputotal = (bentime()-start_time-init_bentime())/1000;
  // Get Test Total Time

  cpuerr = check_pin_errors( bistpoll_pins, _CHECK_FERR );
  // Boot����Error�o�͂�APG�p�^�����璊�o(DPASSDEND_CP�̔�r����)
