  load_vlf_offset(_SUB_MODEENTRY_DAXS,4,tempo1);

  if(SelectPowerSupply(MNORMAL,vcc)) {
  //�e�d���̋�����Level�̐ݒ�(DAXS�]���p)
    vcc[0]=vs0;
    vcc[1]=vs1;
    vcc[2]=vs2;
    return(HWFAIL);
  }
  SetVohVolVtt( daxs_trans.voh, daxs_trans.vol, daxs_trans.vtt, daxs_datao_pin );
  //�I�[��R�⃍�W�J��Pin��H/L����̓d���ݒ�(DAXS�]���p)
  vcc[0]=vs0;
  vcc[1]=vs1;
  vcc[2]=vs2;

    // ******* Read RAM data ********
  for( cnt=RAM_TOP; cnt<=RAM_END; cnt=cnt+4 ) WriteEcrMode8( cnt, 0xFFFFFFFF, SIZE_L );

  RAMRunApg( 2, RAM_TOP, RAM_END );
  // RAM->ECR ReadOut

  if( NULL!=strstr( pat, "read_dump") ){
    if( ReadEcrMode8( RAM_TOP + 0x50, SIZE_L ) ){ tempo1 = 0xC000; tempo2 = 64; }
    else                                        { tempo1 = 0x28000; tempo2 = 512; }
    // UIAREA
    for( cnt=RAM_TOP+0x8000; cnt<=RAM_TOP+tempo1; cnt++ ) write_ecr( cnt, 0xFF );
    RAMRunApg( 2, RAM_TOP + 0x8000, RAM_TOP + 0x8000 + tempo2*0x100 + 0xFF );
    // RAM->ECR ReadOut
  }
  if( CheckFK(FK_DISP_DEBUG) ){ DispEcrBmData(0x0 , 0x0100, DISP_ECR|DISP_1 ); DispEcrBmData(0x3D00 , 0x0100, DISP_ECR|DISP_1 ); }


// ******* end manage ********
  DeviceLevelsPowerDown();
  //�e�d��OFF�R�}���h

  if( cpuerr==1 ){
    if( ReadEcrMode8(0x3D00,SIZE_L)==0xAAAAAAAA ){
              //printf("Test FAIL!!!  %08X %d", ReadEcrMode8(0x3D00,SIZE_L), cpuerr );
       printf("-- FAIL -- Cpu total=%dms",Cputotal);
       return(FAIL);
    }else if( ReadEcrMode8(0x3D00,SIZE_L)==0x55555555 ){
              //printf("Test PASS!!!  %08X %d", ReadEcrMode8(0x3D00,SIZE_L), cpuerr );
       printf("** PASS ** Cpu Total=%dms",Cputotal);
       return(PASS);
    }else{
              //printf("Test ECR data ERROR!!!");
       DispEcrBmData(0x3D00 , 0x0100, DISP_ECR|DISP_1 );
       printf("-- FLAG_FAIL -- Cpu Total=%dms",Cputotal);
       return(FLGFAIL);
    }
  }
  printf("-- FAIL -- !!! TimeOver !!! total=%dms",Cputotal);

  return(CPUFAIL);
}

