int CpuLPReadMode(int mode,int mode_sram,int vcc[NUM_POWERSUPPLY],int waittime,interface_t* param,char *pat,char *mess)
{
    // --------------------------------------------------------------------------
    // Values
    // --------------------------------------------------------------------------
  int i, cnt, cpuerr, datasize, patsize, vs0, vs1, vs2, speed, temp,vtemp[NUM_POWERSUPPLY];
  int result, start_time,old_reg,tempo1,bm_data,ecr_data;
  char mat_str[20];
  char disp_addres[256];

    // --------------------------------------------------------------------------
    // Initialyze
    // --------------------------------------------------------------------------
  cnt = cpuerr = datasize = patsize = vs0 = vs1 = vs2 = speed = tempo1 = 0;
  DispAddres(param,"",disp_addres);

  for( cnt=RAM_TOP; cnt<=RAM_END; cnt=cnt+4 ){
      WriteBmMode8( cnt, 0xFFFFFFFF, SIZE_L );
      WriteEcrMode8( cnt, 0xFFFFFFFF, SIZE_L );
  }


// ****** GET PARAMETER ******
  speed=GetValue(IN_EXTAL1,param);

// ****** DISP TAITOL ******
    //Vref��VrefH�̋L�q�ɕύX�K�v�H
  sprintf(outbuf,"TEST:%d [ %s ] vcc=%dmV ext_Vrefh=%dmV ext_Vref=%dmV F=%2dns PLL=%d(X%d) ", test++,mess,vcc[0],vcc[1],vcc[2],speed,GetValue(IN_PLLON,param),GetValue(IN_PLL_MULT,param));
  DataOut(Ffpt,outbuf);
  sprintf(outbuf,"Module:%s%s", DispMatName(mat_str,param),disp_addres);
  DataOut(Ffpt,outbuf);
    //Ldata�̌����ɕύX����K�v�L
  sprintf(outbuf,"BDATA00:%08X, LDATA0:%08X" ,GetValue(IN_BDATA00,param),GetValue(IN_LDATA0,param));
  DataOut(Ffpt,outbuf);

// ******* BGR Code Check ********
  BGR_REG_CHECK(vcc[0],param);

// ****** SETUP ECR/BM ******
  Ecrsetup8(ECR_OVERL);

// ******* RATE SetUp ********
  SetTimming_NS( daxs_trans.write_rate );

// ******* PowerUp ********
  vs0=vcc[0];
  vs1=vcc[1];
  vs2=vcc[2];

  vcc[0]=daxs_trans.vcc;
  vcc[1]=daxs_trans.vrefh;
  vcc[2]=daxs_trans.vref;

    // ******* APG SetUp(Power) ********
  tempo1=0;
  if((vcc[1] != 0) && (vcc[2] != 0)){
    tempo1 = tempo1 + 0x01;
    //ext_vref ON
    sprintf(outbuf," Ext_Vref  ON  ");
    DataOut(Ffpt,outbuf);
  }else{
    sprintf(outbuf," Ext_Vref  OFF ");
    DataOut(Ffpt,outbuf);
  }


  load_vlf_offset(_SUB_MODEENTRY_DAXS,4,tempo1);

  if(SelectPowerSupply(mode,vcc)) {
  //�e�d���̋�����Level�̐ݒ�(DAXS�]���p)
    vcc[0]=vs0;
    vcc[1]=vs1;
    vcc[2]=vs2;
    return(HWFAIL);
  }
  SetVohVolVtt( daxs_trans.voh, daxs_trans.vol, daxs_trans.vtt, daxs_datao_pin );
  //�I�[��R�⃍�W�J��Pin��H/L����̓d���ݒ�(DAXS�]���p)
  vcc[0]=vs0;
  vcc[1]=vs1;
  vcc[2]=vs2;

// ****************************************************************************
// Write BM
// ****************************************************************************

// ****** MAKE ASM PATH ******
  strcpy( binpat, glob_cdp ); strcat( binpat, glob_binpat_at );
  strcat( binpat, pat );

  patsize = CheckPatLength(binpat) - PAT_FILE_HEADER_SIZE;

// ******* FILE BM WRITE *********
  datasize = comp_load_bm (binpat);
  // comp_load_bm:file pattern => BM


  if(FAIL==datasize) {
  // path/fail check
    sprintf(outbuf," !!! NOT OPEN FILE PATH -> %s (checksum:H'%X) !!!",binpat,datasize);
    DataOut(Ffpt,outbuf);
    DeviceLevelsPowerDown();
    return(NOPATFAIL);
  }else{
    sprintf(outbuf," LOAD FILE PATH -> %s (checksum:H'%X)",binpat,datasize);
    DataOut(Ffpt,outbuf);
  }


    // ******* Parameter BM Write ********
  result = ParamTransBM(param);


    // ** Trans Check **
  if(PASS!=result){
    sprintf(outbuf,"  TRANS ERROR!!  (param => BM) ");
    DataOut(Ffpt,outbuf);
    return(RAMFAIL);
  }else{
    sprintf(outbuf,"  TRANS CHECK OK (param => BM) ");
    DataOut(Ffpt,outbuf);
  }



  strcpy( binpat, glob_cdp ); strcat( binpat, glob_binpat_at );

// if(strcmp(pat,"devicefunction_at.pat")==0) strcat( binpat, "RC04EX_WT1_P1060_V000100.pat" ); else if(strcmp(pat,"readall_code_at.pat")==0) strcat( binpat, "RC04EX_WT1_P3011_V000100.pat" ); else if(strcmp(pat,"erase_code_at.pat")==0) strcat( binpat, "RC04EX_WT1_P2000_V000100.pat" ); else if(strcmp(pat,"programall_code_at.pat")==0) strcat( binpat, "RC04EX_WT1_P1920_V000100.pat" ); else if(strcmp(pat,"program55AA_code_at.pat")==0) strcat( binpat, "RC04EX_WT1_P1920_V000100.pat" ); else if(strcmp(pat,"readcount_code_at.pat")==0) strcat( binpat, "RC04EX_WT1_P3011_V000100.pat" ); else if(strcmp(pat,"settrimingdata_code_at.pat")==0) strcat( binpat, "RC04EX_WT1_P1100_V000100.pat" ); else if(strcmp(pat,"readdump_code_at.pat")==0) strcat( binpat, "RC04EX_WT1_P3011_V000100.pat" ); else { printf("parameter file nothing!!"); return(FAIL); } CheckPatLength(binpat); comp_load_bm (binpat);

  WriteBmMode8( 0x3C00 , 0x00100000, SIZE_L );
  // Dummy Data 18/04/11 Aoki


// ****************************************************************************
// DAXS Transport
// ****************************************************************************
  sprintf(outbuf," ----- RAM transfer Start -----");DataOut(Ffpt,outbuf);

  ParamConditionDisp(PDIN_ALL,0,param);
  //���͗pIF�̏o��

    // ******* Start tests ********
  printf("Write RAM ");
  // Print Retry Count

  if(PASS!=result){
    return(RAMFAIL);
  }


  printf("Read RAM ");
  // Print Retry Count

  set_strobe_mask(daxs_datao_pin);
  //Compare Setting command

    result = RAMRunApg( 2, RAM_TOP, OUTPUTIF_END );
    // DAXS transport 0=write command

  for(i=RAM_TOP;i<=OUTPUTIF_END;i=i+4){
    bm_data=ReadBmMode8(i,SIZE_L);
    ecr_data=ReadEcrMode8(i,SIZE_L);
    if(bm_data!=ecr_data){
      printf("BM <=> ECR Comp ERROR!!! Addr = %X, BM = %X, ECR = %X ",i,bm_data,ecr_data);
      result = FAIL;
    }
  }

  if(PASS!=result){
    return(RAMFAIL);
  }

  sprintf(outbuf," <<<<< EXTRAM transfer OK >>>>>");
  DataOut(Ffpt,outbuf);
  //CommentOut for RAMBOOT Check

// ****************************************************************************
// DAXS RAMBOOT
// ****************************************************************************
  sprintf(outbuf," ----- RAMBOOT Start -----");
  DataOut(Ffpt,outbuf);

    // ** Power Change **
  vs0 = vcc[0];
  vcc[0] = 3300;
  if(SelectPowerSupply(mode,vcc)) {
  //�e�d���̋�����Level�̐ݒ�(RAMBoot�]���p)
    return(HWFAIL);
  }

  if(VccSlow(vs0,vcc[0])){
    return(HWFAIL);
  }
  vcc[0] = vs0;

    // ** Comp Pin SetUp **
  set_strobe_mask(bistpoll_pins);
  // ��rPin�̐ݒ�(RAMBoot�����܂ł̑ҋ@���ԂɎg�p)
  select_vector_mode(poll_pins,_PE_VECTOR_MODE);
  //180314 Add-morioka For RamBoot
  reconnect_pin(poll_pins);
  //180314 Add-morioka For RamBoot
  select_vector_mode(lp_clk,_PE_VECTOR_MODE);
  // APG mode select


    // ** Test Speed SetUp **
    //SetTimming_NS(speed);
  ChangeTimming_GTSLTS( EXTCYLJ, 1, MODEENTRY_SPEED );
  // ModeEntry���g���ݒ� GTS=1,20MHz
  ChangeTimming_GTSLTS( EXTCYLM, 0, speed );
  // ModeEntry���g���ݒ� GTS=1,20MHz

    // ******* APG SetUp(Power) ********
  tempo1=0;
