      run_apg(_RAM_BOOT_MONITOR_END);
      // RAM Boot End(APG)
    set_vlimit(0);
    // PMU 0V
    reconnect_pin(v5_pin);
    // PMU reconnect PNN
    set_invert_mask(no_pin);
    // �K�v�����H

    cpuerr = check_pin_errors( bistpoll_pins, 4 );
    // Boot����Error�o�͂�APG�p�^�����璊�o(DPASSDEND_CP�̔�r����)
    Cputotal = (bentime()-start_time-init_bentime())/1000;
    // Get Test Total Time

// ****************************************************************************
// DAXS Read
// ****************************************************************************

  set_strobe_mask(daxs_datao_pin);
  SetTimming_NS( daxs_trans.read_rate );
  select_vector_mode(poll_pins,_PE_APG_MODE);
  reconnect_pin(poll_pins);

    // ******* PowerUp ********
  vs0=vcc[0];
  vs1=vcc[1];
  vs2=vcc[2];

  vcc[0]=daxs_trans.vcc;
  vcc[1]=daxs_trans.vrefh;
  vcc[2]=daxs_trans.vref;

    // ******* APG SetUp(Power) ********
  tempo1=0;
  if((vcc[1] != 0) && (vcc[2] != 0)){
    tempo1 = tempo1 + 0x01;
    //ext_vref ON
    sprintf(outbuf," Ext_Vref  ON  ");
    DataOut(Ffpt,outbuf);
  }else{
    sprintf(outbuf," Ext_Vref  OFF ");
    DataOut(Ffpt,outbuf);
  }

  load_vlf_offset(_SUB_MODEENTRY_DAXS,4,tempo1);

  if(VccSlow(3300,vs0)){
    return(HWFAIL);
  }


  if(SelectPowerSupply(mode,vcc)) {
  //�e�d���̋�����Level�̐ݒ�(DAXS�]���p)
    vcc[0]=vs0;
    vcc[1]=vs1;
    vcc[2]=vs2;
    return(HWFAIL);
  }
  SetVohVolVtt( daxs_trans.voh, daxs_trans.vol, daxs_trans.vtt, daxs_datao_pin );
  //�I�[��R�⃍�W�J��Pin��H/L����̓d���ݒ�(DAXS�]���p)
  vcc[0]=vs0;
  vcc[1]=vs1;
  vcc[2]=vs2;

    // ******* Read RAM data ********

  for( cnt=RAM_TOP; cnt<=RAM_END; cnt++ ){
      WriteEcrMode8( cnt, 0xFF, SIZE_B );
  }

  result = RAMRunApg( 2, 0x2A00, OUTPUTIF_END );
  // DAXS transport 0=write command
  RAMRunApg( 2, FBM_READTOP ,(FBM_READTOP + FBM_READSIZE - 1) );
  // Daxs Trans For FBM

  if((ReadEcrMode8(0x3D00,SIZE_B)==0xAA) &&
     (ReadEcrMode8(0x3D01,SIZE_B)==0xAA) &&
     (ReadEcrMode8(0x3D02,SIZE_B)==0xAA) &&
     (ReadEcrMode8(0x3D03,SIZE_B)==0xAA) ){
      printf("WT mode Test FAIL!!!");
  }else if((ReadEcrMode8(0x3D00,SIZE_B)==0x55) &&
           (ReadEcrMode8(0x3D01,SIZE_B)==0x55) &&
           (ReadEcrMode8(0x3D02,SIZE_B)==0x55) &&
           (ReadEcrMode8(0x3D03,SIZE_B)==0x55) ){
      printf("WT mode Test PASS!!!");
  }else{
      printf("WT mode Test ECR data ERROR!!!");
      DispEcrBmData(0x3D00 , 0x00FF, DISP_ECR|DISP_1 );
  }

  DeviceLevelsPowerDown();
  //�e�d��OFF�R�}���h

// ****************************************************************************
// EndManage
// ****************************************************************************

    // ******* get data ********
    //ECR => param
  for(cnt=IN_LWORDEND+1;cnt<OUT_BYTEEND;cnt++){
    (param + cnt) -> value = ReadEcrMode8((param + cnt) -> addr,(param + cnt) -> size);
  }
  for(cnt=OUT_BYTEEND+1;cnt<OUT_LWORDEND;cnt++){
    (param + cnt) -> value = ReadEcrMode8((param + cnt) -> addr,(param + cnt) -> size);
  }
  CpuModeOutput(mode,param);

  if(cpuerr == 1) {
    switch(GetValue(OUT_JUDGE1,param)) {
      case CPASS:
        sprintf(outbuf,"** PASS ** Cpu Total=%dms",Cputotal);
        DataOut(Ffpt,outbuf);
        break;
      case CFAIL:
        sprintf(outbuf,"-- FAIL -- Cpu total=%dms",Cputotal);
        DataOut(Ffpt,outbuf);
        break;
      case CFLAG:
        sprintf(outbuf,"-- FLAG_FAIL -- Cpu Total=%dms",Cputotal);
        DataOut(Ffpt,outbuf);
        break;
      case READFAIL:
        sprintf(outbuf,"-- READ_FAIL -- Cpu Total=%dms",Cputotal);
        DataOut(Ffpt,outbuf);
        break;
      default:
        sprintf(outbuf,"-- FAIL -- None (%04X) %dms",((0x00FF&GetValue(OUT_JUDGE1,param))<<8)|((0xFF00&GetValue(OUT_JUDGE1,param))>>8),Cputotal);
        DataOut(Ffpt,outbuf);
        break;
    }
  }else{
    sprintf(outbuf,"-- FAIL -- !!! TimeOver !!! total=%dms",Cputotal);
    DataOut(Ffpt,outbuf);
        //return(FAIL);
  }

    // ******* Monitor Result ********

  if(mode & MONITOR_MODE){
    switch(mode & 0x0000FFFF){
      case  MVSSMON:
      case  MVSSMON_CH:
      case  MVSSMON_20K:
        sprintf(outbuf,"  Monitor Result VSSMON = %dmV",*selvol);
        DataOut(Ffpt,outbuf);
        break;
      case  MVCCMON:
        sprintf(outbuf,"  Monitor Result VCCMON = %dmV",*selvol);
        DataOut(Ffpt,outbuf);
        break;
      case  MVRSGMON:
        sprintf(outbuf,"  Monitor Result VRSGMON = %dmV",*selvol);
        DataOut(Ffpt,outbuf);
        break;
      case  MVCLMON:
        sprintf(outbuf,"  Monitor Result VCLMON = %dmV",*selvol);
        DataOut(Ffpt,outbuf);
        break;
      default:
        printf("Result Setting Error!! mode code = %X",mode);
        return(FAIL);
        break;
    }
    selvol = center;
  }else if(mode & APPLY_MODE){
    switch(selmode){
      case  AUTOTRIM_VDD:
        break;
      case  AUTOTRIM_READDELAY8:
      case  AUTOTRIM_READDELAY10:
        sprintf(outbuf,"  Target Read Delay = %dns",*selvol);
        DataOut(Ffpt,outbuf);
        break;
    }
    if(GetValue(OUT_JUDGE1,param) == 0x00){
      sprintf(outbuf," AutoTrim Pass Input Voltage = %d",*selvol);
      DataOut(Ffpt,outbuf);
    }else if(GetValue(OUT_JUDGE1,param) == FAIL_TAP_TOP ){
      sprintf(outbuf," AutoTrim Error!!! Tap Top Hit");
      DataOut(Ffpt,outbuf);
    }else if(GetValue(OUT_JUDGE1,param) == FAIL_TAP_END ){
      sprintf(outbuf," AutoTrim Error!!! Tap Top Hit");
      DataOut(Ffpt,outbuf);
    }else if(GetValue(OUT_JUDGE1,param) == PASS ){
      sprintf(outbuf," AutoTrim PASS Tap Middle Hit");
      DataOut(Ffpt,outbuf);
    }else{
      sprintf(outbuf," AutoTrim JUDGE = 0x%04X",((0x00FF&GetValue(OUT_JUDGE1,param))<<8)|((0xFF00&GetValue(OUT_JUDGE1,param))>>8));
      DataOut(Ffpt,outbuf);
    }
    if( ( ReadEcrMode8( 0x3D00, SIZE_L )==0x55555555
    // TEST_PASS
      switch( selmode ){
        case AUTOTRIM_VREF10:    printf( " ETLR11 = 0x%02X ->> 0x%02X ", GetValue(IN_ETLR11,param), GetValue(OUT_ETLR11,param) );
                                 SetValue(IN_ETLR11,param,GetValue(OUT_ETLR11,param)); break;
        case AUTOTRIM_VPP_E:     printf( " ETLR20 = 0x%02X ->> 0x%02X ", GetValue(IN_ETLR20,param), GetValue(OUT_ETLR20,param) );
                                 SetValue(IN_ETLR20,param,GetValue(OUT_ETLR20,param)); break;
        case AUTOTRIM_VPP_P:     printf( " ETLR20 = 0x%02X ->> 0x%02X ", GetValue(IN_ETLR20,param), GetValue(OUT_ETLR20,param) );
                                 SetValue(IN_ETLR20,param,GetValue(OUT_ETLR20,param)); break;
        case AUTOTRIM_VPP_PW:    printf( " ETLR21 = 0x%02X ->> 0x%02X ", GetValue(IN_ETLR21,param), GetValue(OUT_ETLR21,param) );
                                 SetValue(IN_ETLR21,param,GetValue(OUT_ETLR21,param)); break;
        case AUTOTRIM_VHH_E:     printf( " ETLR16 = 0x%02X ->> 0x%02X ", GetValue(IN_ETLR16,param), GetValue(OUT_ETLR16,param) );
                                 SetValue(IN_ETLR16,param,GetValue(OUT_ETLR16,param)); break;
        case AUTOTRIM_VHH_P:     printf( " ETLR17 = 0x%02X ->> 0x%02X ", GetValue(IN_ETLR17,param), GetValue(OUT_ETLR17,param) );
                                 SetValue(IN_ETLR17,param,GetValue(OUT_ETLR17,param)); break;
        case AUTOTRIM_VRSG:      printf( " ETLR18 = 0x%02X ->> 0x%02X ", GetValue(IN_ETLR18,param), GetValue(OUT_ETLR18,param) );
                                 SetValue(IN_ETLR18,param,GetValue(OUT_ETLR18,param)); break;
        case AUTOTRIM_V33R:      printf( " ETLR24 = 0x%02X ->> 0x%02X ", GetValue(IN_ETLR24,param), GetValue(OUT_ETLR24,param) );
                                 SetValue(IN_ETLR24,param,GetValue(OUT_ETLR24,param)); break;
        case AUTOTRIM_VWI:       printf( " ETLR19 = 0x%02X ->> 0x%02X ", GetValue(IN_ETLR19,param), GetValue(OUT_ETLR19,param) );
                                 SetValue(IN_ETLR19,param,GetValue(OUT_ETLR19,param)); break;
        case AUTOTRIM_VNOEMI_PE: printf( " ETLR19 = 0x%02X ->> 0x%02X ", GetValue(IN_ETLR19,param), GetValue(OUT_ETLR19,param) );
                                 SetValue(IN_ETLR19,param,GetValue(OUT_ETLR19,param)); break;
        case AUTOTRIM_IMONI_I01U_NOTEMP:
        case AUTOTRIM_IMONI_FLASH_NOTEMP:
        case AUTOTRIM_IMONI_I01U_TEMP:
        case AUTOTRIM_IMONI_FLASH_TEMP:
          printf( " ETLR08 = 0x%02X ->> 0x%02X ", GetValue(IN_ETLR08,param), GetValue(OUT_ETLR08,param) );
          SetValue(IN_ETLR08,param,GetValue(OUT_ETLR08,param));
          printf( " ETLR09 = 0x%02X ->> 0x%02X ", GetValue(IN_ETLR09,param), GetValue(OUT_ETLR09,param) );
          SetValue(IN_ETLR09,param,GetValue(OUT_ETLR09,param));
          break;
      }
    }
  }else{
    printf("Result Setting Error!! mode code = %X",mode);
    return(FAIL);
  }

  return(PASS);
}

