  SetTimming_NS(speed);
  ChangeTimming_GTSLTS( EXTCYLJ, 1, MODEENTRY_SPEED );
  // ModeEntry���g���ݒ� GTS=1,20MHz

    // ******* APG SetUp(Power) ********
  tempo1=0;
  if((vcc[1] != 0) && (vcc[2] != 0)){
    tempo1 = tempo1 + 0x01;
    //ext_vref ON
    sprintf(outbuf," Ext_Vref  ON  ");
    DataOut(Ffpt,outbuf);
  }else{
    sprintf(outbuf," Ext_Vref  OFF ");
    DataOut(Ffpt,outbuf);
  }

    // ******* APG SetUp(Wait) ********
