  set_pe_resource(dend_pin,PE_VOH,vcc[0]*3/10);
  set_pe_resource(dend_pin,PE_VOL,vcc[0]*3/10);
  set_pe_resource(dend_pin,PE_VTT,vcc[0]*3/10);
    //set_vtt_mask(dend_pin);
  reconnect_pin(dend_pin);

    // ************************** Run APG & Monitor(Apply) *****************************
    start_time = bentime();
    // Get Test Start Time
    load_vlf_offset(_SUB_RAMBT_POLL,0,5);
    // 20ms fix(2000*200*200ns)
    load_vlf_offset(_SUB_RAMBT_DEND_H_POLL,0,6666/speed);
    // 1ms fix
    load_vlf_offset(_SUB_RAMBT_DEND_H_POLL,1,700);
    // 50*1ms
    load_vlf_offset(_SUB_RAMBT_DEND_L_POLL,0,6666/speed);
    // 1ms fix
    load_vlf_offset(_SUB_RAMBT_DEND_L_POLL,1,700);
    // 50*1ms

    run_apg(_RAM_BOOT_MONITOR_CTRL);
    delay_timer( 2000 );
	vol_s = GetValue(IN_LDATA0,param);
	vol_d = GetValue(IN_LDATA1,param);
    set_vlimit(GetValue(IN_LDATA0,param));
    // Set V = 0V
    comp_set_ilimit(250000);
    // I-Limit = 250000nA(250uA) 

    if(GetValue(IN_TESTSEL,param) == 0){
    //Vthsearch  Mode

    for(j=0;j<3;j++){
      if(j==0){
        vol_s = GetValue(IN_LDATA0,param);
	      vol_d = GetValue(IN_LDATA1,param);
      }else{
        vol_s = vol - vol_d;
	      vol_d = vol_d / 5;
      }

	  if(absolute(vol_d) <= absolute(GetValue(IN_LDATA2,param))){
	  //Last Loop�p
	    vol_d = GetValue(IN_LDATA2,param);
		j = 2;
	  }
      for(i=0;i<7;i++){
	      vol = vol_s +(i * vol_d);
		    if(vol > 1250){
		    comp_write_lbreg_pe(RVCCMON);
		    //1.25V�ȏ��VccMon�Ɉ��
		  }else{
		    comp_write_lbreg_pe(RVSSMON);
		    //1.25V�ȉ���VccMon�Ɉ��
		  }
      sprintf(outbuf,"Voltage = %d",vol);
      DataOut(Ffpt,outbuf);
		  set_vlimit(vol);
		  delay_timer(500);
		  //�d���ύX��̈��莞��(�e�X�^�[��)
      run_apg(_RAM_BOOT_DEND_L_WAIT);
      //DPASS�M����L�҂�
		  delay_timer(500);
      run_apg(_RAM_BOOT_DENDWAIT_POLLCHECK);
      //DPASS�M����H�҂�
      sprintf(outbuf,"RESULT = %X",check_pin_errors( dpass_pins, 4 ));
      DataOut(Ffpt,outbuf);

		  if(check_pin_errors( dpass_pins, 4 ) == 1)break;
      }
    }
	  *selvol = vol - vol_d;

    }else if(GetValue(IN_TESTSEL,param) == 1){
    //VthCount Mode
      for(i = 0;i < GetValue(IN_BDATA00,param);i++){
        vol = vol_s + vol_d * i;
		    if(vol > 1250){
		      comp_write_lbreg_pe(RVCCMON);
		      //1.25V�ȏ��VccMon�Ɉ��
		    }else{
		      comp_write_lbreg_pe(RVSSMON);
		      //1.25V�ȉ���VccMon�Ɉ��
		    }
        sprintf(outbuf,"Voltage = %d",vol);
        DataOut(Ffpt,outbuf);
		    set_vlimit(vol);
		    delay_timer(500);
		    //�d���ύX��̈��莞��(�e�X�^�[��)
        run_apg(_RAM_BOOT_DEND_L_WAIT);
        //DPASS�M����L�҂�
		    delay_timer(500);
        run_apg(_RAM_BOOT_DENDWAIT_POLLCHECK);
        //DPASS�M����H�҂�
		    		    //printf("RESULT = %X",check_pin_errors( dpass_pins, 4 ));
		    if(check_pin_errors( dpass_pins, 4 ) == 1)break;
      }
    }
    run_apg(_RAM_BOOT_DEND_L_WAIT);
    //DPASS�M����H�҂�

        // ************************* RAMBoot End Manage ***********************************
        // ** Comp Pin SetUp **
    set_strobe_mask(bistpoll_pins);
    // ��rPin�̐ݒ�(RAMBoot�����܂ł̑ҋ@���ԂɎg�p)
    select_vector_mode(poll_pins,_PE_VECTOR_MODE);
