  char mat_value[100];
  int start_time;
  // Start Time For bentime
  int vs0,vs1,vs2;
  // Power bak
  int old_reg,ilimit;
  char mat_str[20];
  char disp_addres[256];

  flg = 0;
  DispAddres(param,"",disp_addres);

  for( cnt=RAM_TOP; cnt<=(RAM_TOP+0x100); cnt=cnt+4 ){
            //WriteBmMode8( cnt, 0xFFFFFFFF, SIZE_L );
      WriteEcrMode8( cnt, 0xFFFFFFFF, SIZE_L );
  }

    // ****** GET PARAMETER ******
  speed=GetValue(IN_EXTAL1,param);

  pmu_range = UA250;
    // ****** DISP TAITOL ******
    //Vref��VrefH�̋L�q�ɕύX�K�v�H
  sprintf(outbuf,"TEST:%d [ %s ] vcc=%dmV ext_Vrefh=%dmV ext_Vref=%dmV F=%2dns PLL=%d(X%d) ", test++,mess,vcc[0],vcc[1],vcc[2],speed,GetValue(IN_PLLON,param),GetValue(IN_PLL_MULT,param));
  DataOut(Ffpt,outbuf);
  sprintf(outbuf,"Module:%s%s", DispMatName(mat_str,param),disp_addres);
  DataOut(Ffpt,outbuf);

    // ****** SETUP ECR/BM ******
  Ecrsetup8(ECR_OVERL);

    // ******* RATE SetUp ********
  SetTimming_NS( daxs_trans.write_rate );

    // ******* PowerUp ********
