  }

  if(VccSlow(vs0,vcc[0])){
    return(HWFAIL);
  }
  vcc[0] = vs0;

    // ** Comp Pin SetUp **
  set_strobe_mask(bistpoll_pins);
  // ��rPin�̐ݒ�(RAMBoot�����܂ł̑ҋ@���ԂɎg�p)
  select_vector_mode(poll_pins,_PE_VECTOR_MODE);
  //180314 Add-morioka For RamBoot
  reconnect_pin(poll_pins);
  //180314 Add-morioka For RamBoot

    // ** Test Speed SetUp **
  SetTimming_NS(speed);
  ChangeTimming_GTSLTS( EXTCYLJ, 1, MODEENTRY_SPEED );
  // ModeEntry���g���ݒ� GTS=1,20MHz

    // ******* APG SetUp(Power) ********
  tempo1=0;
  if((vcc[1] != 0) && (vcc[2] != 0)){
    tempo1 = tempo1 + 0x01;
    //ext_vref ON
    sprintf(outbuf," Ext_Vref  ON  ");
    DataOut(Ffpt,outbuf);
  }else{
    sprintf(outbuf," Ext_Vref  OFF ");
    DataOut(Ffpt,outbuf);
  }

    // ******* APG SetUp(Wait) ********
  load_vlf_offset(_SUB_MODEENTRY_RAM,6,  1000/MODEENTRY_SPEED);
  // 1us Wait
  load_vlf_offset(_SUB_MODEENTRY_RAM,1,300000/2/MODEENTRY_SPEED);
  // 300us Wait
  load_vlf_offset(_SUB_MODEENTRY_RAM,2, 70000/MODEENTRY_SPEED);
  // 70ms Wait
  load_vlf_offset(_SUB_MODEENTRY_RAM,3,tempo1);
  // Vdd/Vddh On/Off
  load_vlf_offset(_SUB_RAMBT_END,0,500*waittime/speed);
  // RAMBootEnd Wait = waittime x(500x200x2000ns)

    // ************** PMU Setting *******************
    //Iref Monitor setting
  connect_ps(PPS_CON_VNN1,PPS_CMODE_PMU);
  pmu_range = UA25;
	set_pmu_range(pmu_range);
	comp_set_ilimit(25000);
	// 25000nA = 25uA
	set_vlimit(650);
	// Set V = 0.65V
	delay_timer( 100 );

    // ** Comp Pin SetUp **
  set_strobe_mask(dpass_pins);
  // ��rPin�̐ݒ�(RAMBoot�����܂ł̑ҋ@���ԂɎg�p)
  select_vector_mode(dpass_pins,_PE_VECTOR_MODE);
  //180314 Add-morioka For RamBoot
  SetVohVolVtt( 75*vcc[0]/100, 75*vcc[0]/100, 5*vcc[0]/10 , bistpoll_pins );
  //�I�[��R�⃍�W�J��Pin��H/L����̓d���ݒ�(DAXS�]���p)
  reconnect_pin(dpass_pins);

    // ************************** Run APG & Monitor(Apply) *****************************
    start_time = bentime();
    // Get Test Start Time
    load_vlf_offset(_SUB_RAMBT_POLL,0,500/speed);
    // 20ms fix(2000*200*200ns)
    load_vlf_offset(_SUB_RAMBT_DPASS_H_POLL,0,0xFF/speed);
    // 20ms fix(2000*200*200ns)
    load_vlf_offset(_SUB_RAMBT_DPASS_H_POLL,1,100*0x5FB/100);
    // 20ms fix(2000*200*200ns)
    load_vlf_offset(_SUB_RAMBT_DPASS_L_POLL,0,0xFF/speed);
    // 20ms fix(2000*200*200ns)
    load_vlf_offset(_SUB_RAMBT_DPASS_L_POLL,1,100*0x5FB/100);
    // 20ms fix(2000*200*200ns)


    run_apg(_RAM_BOOT_MONITOR_CTRL);
    delay_timer( 2000 );

    run_apg(_RAM_BOOT_DPASS_H_POLL);
    //DPASS�M����H�҂�
    delay_timer( 1000 );

    SITE_MASK (1, read_pmu_status(0x08));
    // I measurement
    SITE_MASK (1, *(selvol)=read_adc_ave(ADC_IMEAS,0,100));
	printf("1st : Iref = %dnA",*(selvol));

    run_apg(_RAM_BOOT_DPASS_L_POLL);
    //DPASS�M����L�҂�
    delay_timer( 1000 );

    for(i=0;i<GetValue(IN_BDATA00,param);i++){
      set_vlimit(650);
      run_apg(_RAM_BOOT_DPASS_H_POLL);
      //DPASS�M����H�҂�
      delay_timer( 1000 );

      SITE_MASK (1, read_pmu_status(0x08));
      // I measurement
      SITE_MASK (1, *(selvol+i+1)=read_adc_ave(ADC_IMEAS,0,100));

      if((*(selvol+i+1) >= 24000) && (pmu_range == UA25)){
      //�d���l��24uA�ȏ�̎��͓d�����j�^�[�����Up���đ���
	      pmu_range = UA250;
        set_pmu_range(pmu_range);
		    comp_set_ilimit(250000);
		    // 250000nA = 250uA
	  	  delay_timer( 100 );
        SITE_MASK (1, read_pmu_status(0x08));
        // I measurement
        SITE_MASK (1, *(selvol+i+1)=read_adc_ave(ADC_IMEAS,0,100));
		  }
	  printf("%dkai : Iref_T = %dnA",i,*(selvol+1+i));

      run_apg(_RAM_BOOT_DPASS_L_POLL);
      //DPASS�M����L�҂�
      delay_timer( 1000 );
	  set_vlimit(0);
      for(j=0;j<GetValue(IN_BDATA01,param);j++){
        run_apg(_RAM_BOOT_DPASS_H_POLL);
        //DPASS�M����H�҂�
        delay_timer( 1000 );

        if((j+1) == GetValue(IN_BDATA01,param)){
          VccSlow(*(vc1+0),*(vc1+j));
          set_vih2(*(vc2+0));
          comp_set_v3(*(vc3+0));
	    printf("%dkai : PowerChange Vcc = %d, Vddh = %d, Vdd = %d",j,*(vc1),*(vc2),*(vc3));
        }else{
          VccSlow(*(vc1+j+1),*(vc1+j));
          set_vih2(*(vc2+j+1));
          comp_set_v3(*(vc3+j+1));
	    printf("%dkai : PowerChange Vcc = %d, Vddh = %d, Vdd = %d",j,*(vc1+j+1),*(vc2+j+1),*(vc3+j+1));
        }
        delay_timer( 1000 );

        run_apg(_RAM_BOOT_DPASS_L_POLL);
        //DPASS�M����L�҂�
        delay_timer( 1000 );
      }
    }


        // ************************* RAMBoot End Manage ***********************************
        // ** Comp Pin SetUp **
    set_strobe_mask(bistpoll_pins);
    // ��rPin�̐ݒ�(RAMBoot�����܂ł̑ҋ@���ԂɎg�p)
    select_vector_mode(poll_pins,_PE_VECTOR_MODE);
    //180314 Add-morioka For RamBoot
    SetVohVolVtt( 2*vcc[0]/10, 2*vcc[0]/10, 5*vcc[0]/10 , bistpoll_pins );
    //�I�[��R�⃍�W�J��Pin��H/L����̓d���ݒ�(DAXS�]���p)

            //load_vlf_offset(_SUB_RAMBT_END,1,1000); // 50*cycle
      load_vlf_offset(_SUB_RAMBT_END,0,500*W1SEC*2/speed);
      // RAMBootEnd Wait = waittime x(500x200x2000ns)
      run_apg(_RAM_BOOT_MONITOR_END);
      // RAM Boot End(APG)
    set_vlimit(0);
    // PMU 0V
    reconnect_pin(v5_pin);
    // PMU reconnect PNN
    set_invert_mask(no_pin);
    // �K�v�����H

    cpuerr = check_pin_errors( bistpoll_pins, 4 );
    // Boot����Error�o�͂�APG�p�^�����璊�o(DPASSDEND_CP�̔�r����)
    Cputotal = (bentime()-start_time-init_bentime())/1000;
    // Get Test Total Time

// ****************************************************************************
// DAXS Read
// ****************************************************************************

  set_strobe_mask(daxs_datao_pin);
  SetTimming_NS( daxs_trans.read_rate );
  select_vector_mode(poll_pins,_PE_APG_MODE);
  reconnect_pin(poll_pins);

    // ******* PowerUp ********
  vs0=vcc[0];
  vs1=vcc[1];
  vs2=vcc[2];

  vcc[0]=daxs_trans.vcc;
  vcc[1]=daxs_trans.vrefh;
  vcc[2]=daxs_trans.vref;

    // ******* APG SetUp(Power) ********
  tempo1=0;
  if((vcc[1] != 0) && (vcc[2] != 0)){
    tempo1 = tempo1 + 0x01;
    //ext_vref ON
    sprintf(outbuf," Ext_Vref  ON  ");
    DataOut(Ffpt,outbuf);
  }else{
    sprintf(outbuf," Ext_Vref  OFF ");
    DataOut(Ffpt,outbuf);
  }

  load_vlf_offset(_SUB_MODEENTRY_DAXS,4,tempo1);

  if(VccSlow(3300,vs0)){
    return(HWFAIL);
  }


  if(SelectPowerSupply(mode,vcc)) {
  //�e�d���̋�����Level�̐ݒ�(DAXS�]���p)
    vcc[0]=vs0;
    vcc[1]=vs1;
    vcc[2]=vs2;
    return(HWFAIL);
  }
  SetVohVolVtt( daxs_trans.voh, daxs_trans.vol, daxs_trans.vtt, daxs_datao_pin );
  //�I�[��R�⃍�W�J��Pin��H/L����̓d���ݒ�(DAXS�]���p)
  vcc[0]=vs0;
  vcc[1]=vs1;
  vcc[2]=vs2;

    // ******* Read RAM data ********

  for( cnt=0x2000; cnt<=OUTPUTIF_END; cnt+=4 ){
      WriteEcrMode8( cnt, 0xFFFFFFFF, SIZE_L );
  }

  result = RAMRunApg( 2, 0x2000, OUTPUTIF_END );
  // DAXS transport 0=write command

  if((ReadEcrMode8(0x3D00,SIZE_B)==0xAA) &&
     (ReadEcrMode8(0x3D01,SIZE_B)==0xAA) &&
     (ReadEcrMode8(0x3D02,SIZE_B)==0xAA) &&
     (ReadEcrMode8(0x3D03,SIZE_B)==0xAA) ){
      printf("WT mode Test FAIL!!!");
  }else if((ReadEcrMode8(0x3D00,SIZE_B)==0x55) &&
           (ReadEcrMode8(0x3D01,SIZE_B)==0x55) &&
           (ReadEcrMode8(0x3D02,SIZE_B)==0x55) &&
           (ReadEcrMode8(0x3D03,SIZE_B)==0x55) ){
      printf("WT mode Test PASS!!!");
  }else{
      printf("WT mode Test ECR data ERROR!!!");
      DispEcrBmData(0x3D00 , 0x00FF, DISP_ECR|DISP_1 );
  }

  DeviceLevelsPowerDown();
  //�e�d��OFF�R�}���h

// ****************************************************************************
// EndManage
// ****************************************************************************

    // ******* get data ********
    //ECR => param
  for(cnt=IN_LWORDEND+1;cnt<OUT_BYTEEND;cnt++){
    (param + cnt) -> value = ReadEcrMode8((param + cnt) -> addr,(param + cnt) -> size);
  }
  for(cnt=OUT_BYTEEND+1;cnt<OUT_LWORDEND;cnt++){
    (param + cnt) -> value = ReadEcrMode8((param + cnt) -> addr,(param + cnt) -> size);
  }
  SetValue(OUT_LDATA0,param,vol);
  CpuModeOutput(mode,param);

  if(cpuerr == 1) {
    switch(GetValue(OUT_JUDGE1,param)) {
      case CPASS:
        sprintf(outbuf,"** PASS ** Cpu Total=%dms",Cputotal);
        DataOut(Ffpt,outbuf);
        break;
      case CFAIL:
        sprintf(outbuf,"-- FAIL -- Cpu total=%dms",Cputotal);
        DataOut(Ffpt,outbuf);
        break;
      case CFLAG:
        sprintf(outbuf,"-- FLAG_FAIL -- Cpu Total=%dms",Cputotal);
        DataOut(Ffpt,outbuf);
        break;
      case READFAIL:
        sprintf(outbuf,"-- READ_FAIL -- Cpu Total=%dms",Cputotal);
        DataOut(Ffpt,outbuf);
        break;
      default:
        sprintf(outbuf,"-- FAIL -- None (%04X) %dms",((0x00FF&GetValue(OUT_JUDGE1,param))<<8)|((0xFF00&GetValue(OUT_JUDGE1,param))>>8),Cputotal);
        DataOut(Ffpt,outbuf);
        break;
    }
  }else{
    sprintf(outbuf,"-- FAIL -- !!! TimeOver !!! total=%dms",Cputotal);
    DataOut(Ffpt,outbuf);
        //return(FAIL);
  }

    // ******* Monitor Result ********


  return(PASS);
}

