// 250ns (ECR R/W cycle)

// --------- Normal cycle define --------------------------------------
#define NSEC950     t=18,   inv_en,vhh_en
// 950ns m_clock cycle
#define NSEC900     t=17,   inv_en,vhh_en
// 900ns m_clock cycle
#define NSEC850     t=16,   inv_en,vhh_en
// 850ns m_clock cycle
#define NSEC800     t=15,   inv_en,vhh_en
// 800ns m_clock cycle
#define NSEC750     t=14,   inv_en,vhh_en
// 750ns m_clock cycle
#define NSEC700     t=13,   inv_en,vhh_en
// 700ns m_clock cycle
