int CheckPatLength(char * patpath)
{
  FILE_T *fpt;
  int cnt;
  if( ( fpt=fopen( patpath, "rb" ) )==NULL ){
  // Open file
    ErrorPrint( patpath ); return( FAIL );
    // fopen Error
  }
  fseek( fpt, 0, SEEK_END );
  // file size get
  cnt = ftell( fpt );
  if( fclose( fpt ) ) exit(-10);
  // Close file Err exit
  return( cnt );
  // file size return
}

int DataOut(int outmode,char *dat)
{
  switch(outmode){
    case 0:
      break;
    case 1:
      printf("%s",dat);
      break;
    case 2:
      printf("%s",dat);
    case 3:
      fprintf(Fptdata,"%s",dat);
      break;
  }
  return(PASS);
}

int DataOut2( int outmode, FILE_T* buff, char* data ){
  if( 0x01&outmode ){
    printf( "%s", data );
  }
  if( 0x02&outmode ){
    fprintf( buff, "%s", data );
  }
  return( PASS );
}

