int strtod(char *str)
{
  int d, base, minus;

  while(isspace(*str)) str++;
  if( '-' == *str ){
    minus = -1;
    str++;
  } else minus = 1;
  if( !strnicmp(str, "0x", 2) ){
    base = 16;
    str += 2;
  } else base = 10;
  for( d = 0; NUL != *str && !isspace(*str); str++ ){
    if( 10 == base ){
      if(!isdigit(*str))    break;
    }
    else{
      if(!isxdigit(*str))   break;
    }
    d *= base;
    d += toint(*str);
  }
  return(d * minus);
}

int strtoh(char *str)
{
  int d, base, minus;

  base = 16;
  while(isspace(*str)) str++;
  if( '-' == *str ){
    minus = -1;
    str++;
  } else minus = 1;
  for( d = 0; NUL != *str && !isspace(*str); str++ ){
    d *= base;
    d += toint(*str);
  }
  return(d * minus);
}

int strtohn(char *str,int byteend)
{
  int d, base, minus, stopinc;

  base = 16;
  while(isspace(*str)) str++;
  if( '-' == *str ){
    minus = -1;
    str++;
  } else minus = 1;
  for( d = 0,stopinc = 0; NUL != *str && !isspace(*str) && byteend > stopinc; str++,stopinc++ ){
    d *= base;
    d += toint(*str);
  }
  return(d * minus);
}

