void StringInput( char *str )
{
  int n, i;
  char  buf[1024];

  fflush( stdout );
  buf[0] = NUL;
  for( i = 0; NULL == fgets(buf, 1024, stdin) && i < 5; i++ );
  n = strlen( buf ) - 1;
  if( n >= 0 && '\n' == buf[n] )  buf[n] = NUL;
  // cut last LF
  strcpy( str, buf );
}

