// ----------------------------------------------------------------------------
// Description Keyboard Any key hit wait loop
// ----------------------------------------------------------------------------
int WaitHitKey( const char *mess ){
  flush_console();
  fflush( stdin );
  printf( "%s", mess );
  fflush( stdout );
  while( !kbhit() );
  flush_console();
  fflush( stdin );
}

// ----------------------------------------------------------------------------
// Description Keyboard Any key hit Check
// ----------------------------------------------------------------------------
int CheckHitKey( void ){
  int retcode;
//  flush_console();
//  fflush(stdin);
  retcode = kbhit();
  flush_console();
  fflush( stdin );
  fflush( stdout );
  return retcode;
}

