// ----------------------------------------------------------------------------
// ECR Input parameter get
// ----------------------------------------------------------------------------
int GetValueEcrIIF( int i ){
  int adr, data;
  adr = INPUTIF_TOP;
  if( i>IN_BYTEEND ){
    adr += IN_BYTEEND-1;
    adr += ( i-IN_BYTEEND-1 )*4;
    data = ReadEcrMode8( adr, SIZE_L );
  }else{
    adr += i;
    data = ReadEcrMode8( adr, SIZE_B );
  }
  return( data );
}

