int StrCut( char *t, char *s, int pos, int len )
{
    if( pos < 0 || len < 0 || len > strlen(s) )
        return FAIL;
    for( s += pos; *s != '\0' && len > 0; len-- )
        *t++ = *s++;
    *t = '\0';
    return PASS;
}


