char *C_time(int *timer)
{
  int i;
  int flag;
  int len;
  char *top;
  char *current;

  top = ctime((CTIME_T*) timer);
  if(NULL==top){
    return(NULL);
  }

  current = top;
  len = strlen(top);
  flag = OFF;
  for( i=0; i<len; i++ ){
    if( isalpha( *(current+i) ) ){
      if( OFF==flag ){
        flag = ON;
      }else if( ON==flag ){
        *(current+i) = (char)tolower( *(current+i) );
      }
    }else{
      flag = OFF;
    }
  }

  return(top);
}

char *CreatePatFileName( char *patternname )
// ===============================================================================================
{
