void ParamInitialize(interface_t* interface)
{
  int taddr,i;

  taddr = INPUTIF_TOP;
  for(i=0;i<IN_BYTEEND;i++){
    interface[i].addr = taddr;
    interface[i].size = 1;
    interface[i].value = 0;
    interface[i].wk = 0;
    taddr+=1;
  }
  for(i=IN_BYTEEND+1;i<IN_LWORDEND;i++){
    interface[i].addr = taddr;
    interface[i].size = 4;
    interface[i].value = 0;
    interface[i].wk = 0;
    taddr+=4;
  }

  taddr = OUTPUTIF_TOP;
  for(i=IN_LWORDEND+1;i<OUT_BYTEEND;i++){
    interface[i].addr = taddr;
    interface[i].size = 1;
    interface[i].value = 0;
    interface[i].wk = 0;
    taddr+=1;
  }
  for(i=OUT_BYTEEND+1;i<OUT_LWORDEND;i++){
    interface[i].addr = taddr;
    interface[i].size = 4;
    interface[i].value = 0;
    interface[i].wk = 0;
    taddr+=4;
  }

  InitialValue(interface);

}

