    interface[i].size = 1;
    interface[i].value = 0;
    interface[i].wk = 0;
    taddr+=1;
  }
  for(i=OUT_BYTEEND+1;i<OUT_LWORDEND;i++){
    interface[i].addr = taddr;
    interface[i].size = 4;
    interface[i].value = 0;
    interface[i].wk = 0;
    taddr+=4;
  }


  pass_bin = 1;
  strcpy( datetime_string, "20110913084500" );

  printf("********************************");
  printf( "%.30s", devicename );
  printf("RAM   : %dKB", RAM_SIZE/1024 );
  printf("********************************");

  if (test_flow == 1){
    if (NORMAL_FLOW || auto_ex_cmd_only){
      if(var1 == 0) {

        printf(" Hello Versa Test World !! ");

        if(DeviceSpecificInit() != PASS){
          printf("Device Initialize Error !!");
          return(FAIL);
        }
        printf("PASS Initialize");

        DeviceSpecificPowerDown();
        printf("PASS SpecificPowerDown");

        if(AnalisysTestProgram(interface,0) != PASS){
          printf("Select Program ERROR !!");
        }
        DeviceSpecificPowerDown();
        PowerDown(1);
        return(PASS);

      }else{
        if(DeviceSpecificInit() != PASS){
          printf("Device Initialize Error !!");
          PowerDown(255);
        }
        printf("PASS Initialize");
        DeviceSpecificPowerDown();
        printf("PASS SpecificPowerDown");

        switch(var1){
        case BWT_FL0:
        case BWT_FL1:
        case BWT_FL2:
        case BWT_FL4:
        case BWT_FL8:
        case BWT_FL9:
        case BWT_FL0D:
        case BWT_FL1D:
        case BWT_FL2D:
        case BWT_FL4D:
        case BWT_FL8D:
        case BWT_FL9D:
        case BFT_FL1:
        case BFT_FL2:
        case BFT_FL1D:
        case BFT_FL2D:
          result_bin = WaferTestProgram( var1&0x00FF );
          // Wafer Test Versa Emulation
          break;
        // case BGR_WT1: result_bin = BGR_WT(interface,1); break; case BGR_WT2: tempo1 = bentime(); result_bin = BGR_WT_HT(interface); tempo2 = (bentime()-tempo1-init_bentime())/1000; printf(" BGR_WT2 RunTime = %d[ms]",tempo2); break; case BGR_WT4: result_bin = BGR_WT(interface,4); break; case BGR_WT5: result_bin = BGR_WT(interface,5); break;
        case AE_WT:
        	 result_bin = AE_WT1(interface,0);
        	break;
        case AE_WT2:
     	    result_bin = AE_WT1(interface,1);
      	   break;
        case VTHTRIM_WT:
        	result_bin = WT_Vth_Trim(interface);
      	break;
        case WT_F_WS:
        	result_bin = WT_WS_Flash(interface);
        break;
      	case QT_SNO:
      	    result_bin = BGR_QT_NoSet(interface,QT_SampleNo);
            printf("+====================+");
            printf("| Sample No, ->%d",QT_SampleNo);
            printf("+====================+");
