        reg_code[ 2] =  5 & 0x0F;
        reg_code[ 3] =  4 & 0x0F;
        reg_code[ 4] =  3 & 0x0F;
        reg_code[ 5] =  2 & 0x0F;
        reg_code[ 6] =  1 & 0x0F;
        reg_code[ 7] =  0 & 0x0F;
        reg_code[ 8] = 15 & 0x0F;
        reg_code[ 9] = 14 & 0x0F;
        reg_code[10] = 13 & 0x0F;
        reg_code[11] = 12 & 0x0F;
        reg_code[12] = 11 & 0x0F;
        reg_code[13] = 10 & 0x0F;
        reg_code[14] =  9 & 0x0F;
        reg_code[15] =  8 & 0x0F;

      mask  = 0x0F;
      shift = 4;
      loop_st = 0;
      loop_ed = 15;
      break;
    case V_VDD:
      sprintf(filename,"vdd_vsVol");
      testsel_mode = MONITOR_VDD;
      break;
    case V_VDDH:
      sprintf(filename,"vddh_vsVol");
      testsel_mode = MONITOR_VDDH;
      break;
    case V_VPP_E:
      sprintf(filename,"vpp(erase)_vsTAP");
      testsel_mode = MONITOR_VPP_E;
      terminal = VSSMON_MON;
      change_reg = IN_ETLR20;
      for ( i=0 ; i<=15 ; i++ ) reg_code[i] = (0x0 + i) & 0x0F;
      mask  = 0x0F;
      shift = 4;
      loop_st = 0;
      loop_ed = 15;
      break;
    case V_VPP_P:
      sprintf(filename,"vpp(write)_vsTAP");
      testsel_mode = MONITOR_VPP_P;
      terminal = VSSMON_MON;
      change_reg = IN_ETLR20;
      for ( i=0 ; i<=15 ; i++ ) reg_code[i] = (0x0 + i) & 0x0F;
      mask  = 0xF0;
      shift = 0;
      loop_st = 0;
      loop_ed = 15;
      break;
    case V_VPP_PW:
      sprintf(filename,"vpp(pre-write)_vsTAP");
      testsel_mode = MONITOR_VPP_PW;
      terminal = VSSMON_MON;
      change_reg = IN_ETLR21;
      for ( i=0 ; i<=15 ; i++ ) reg_code[i] = (0x0 + i) & 0x0F;
      mask  = 0x0F;
      shift = 4;
      loop_st = 0;
      loop_ed = 15;
      break;
    case V_VHH_E:
      sprintf(filename,"vhh(erase)_vsTAP");
      testsel_mode = MONITOR_VHH_E;
      terminal = VCCMON_MON;
      change_reg = IN_ETLR16;
      for ( i=0 ; i<=63 ; i++ ) reg_code[i] = (0x0 + i) & 0x3F;
      mask  = 0xC0;
      shift = 0;
      loop_st = 0;
      loop_ed = 63;
      break;
    case V_VHH_P:
      sprintf(filename,"vhh(write)_vsTAP");
      testsel_mode = MONITOR_VHH_P;
      terminal = VCCMON_MON;
      change_reg = IN_ETLR17;
      for ( i=0 ; i<=63 ; i++ ) reg_code[i] = (0x0 + i) & 0x3F;
            //for ( i=63 ; i<=0 ; i-- ) reg_code[i] = (0x0 + i) & 0x3F;
      mask  = 0xC0;
      shift = 0;
      loop_st = 0;
      loop_ed = 63;
      break;
    case V_VRSG:
      sprintf(filename,"vrsg_vsTAP");
      testsel_mode = MONITOR_VRSG;
      terminal = VCCMON_MON;
      change_reg = IN_ETLR18;
            //for ( i=0 ; i<=7 ; i++ ) reg_code[i] = (0x0 + i) & 0x07;    // Oo͏ύẌׁARgAEg
      reg_code[0] = 0x1 & 0x07;
      reg_code[1] = 0x0 & 0x07;
      reg_code[2] = 0x3 & 0x07;
      reg_code[3] = 0x2 & 0x07;
      reg_code[4] = 0x5 & 0x07;
      reg_code[5] = 0x4 & 0x07;
      reg_code[6] = 0x7 & 0x07;
      reg_code[7] = 0x6 & 0x07;
      mask  = 0xF8;
      shift = 0;
      loop_st = 0;
      loop_ed = 7;
      break;
    case V_V33R:
      sprintf(filename,"v33r_vsTAP");
