      terminal = VCCMON_MON;
      change_reg = IN_ETLR24;
      for ( i=0 ; i<=7 ; i++ ) reg_code[i] = (0x0 + i) & 0x07;
      mask  = 0xF8;
      shift = 0;
      loop_st = 0;
      loop_ed = 7;
      break;
    case V_VWI:
      sprintf(filename,"vwi_vsTAP");
      testsel_mode = MONITOR_VWI;
      terminal = VCCMON_MON;
      change_reg = IN_ETLR19;
      for ( i=0 ; i<=15 ; i++ ) reg_code[i] = (0x0 + i) & 0x0F;
      mask  = 0x0F;
      shift = 4;
      loop_st = 0;
      loop_ed = 15;
      break;
    case V_VDEMG:
      sprintf(filename,"vdemg_vsTAP");
      testsel_mode = MONITOR_VDEMG;
      terminal = VSSMON_MON;
      change_reg = IN_ETLR21;
      for ( i=0 ; i<=15 ; i++ ) reg_code[i] = (0x0 + i) & 0x0F;
      mask  = 0xF0;
      shift = 0;
      loop_st = 0;
      loop_ed = 15;
      break;
    case V_VNOEMI_PE:
      sprintf(filename,"vnoemi(PE)_vsTAP");
      testsel_mode = MONITOR_VNOEMI_PE;
      terminal = VCCMON_MON;
      change_reg = IN_ETLR19;
      for ( i=0 ; i<=15 ; i++ ) reg_code[i] = (0x0 + i) & 0x0F;
      mask  = 0xF0;
      shift = 0;
      loop_st = 0;
      loop_ed = 15;
      break;
    case I_IMONI_I01U_NOTEMP:
    case I_IMONI_FLASH_NOTEMP:
      if( mode == I_IMONI_I01U_NOTEMP )  {sprintf(filename,"imoni-i01u(no-temp)_vsTAP");  testsel_mode = MONITOR_IMONI_I01U_NOTEMP;} if( mode == I_IMONI_FLASH_NOTEMP ) {s
      terminal = VSSMON_MON;
      change_reg = IN_ETLR08;
      for ( i=0 ; i<=127 ; i++ ) reg_code[i] = (0x0 + i) & 0x7F;
      mask  = 0x80;
      shift = 0;
      loop_st = 0;
      loop_ed = 127;
      break;
    case I_IMONI_I01U_TEMP:
    case I_IMONI_FLASH_TEMP:
      if( mode == I_IMONI_I01U_TEMP )  {sprintf(filename,"imoni-i01u(temp)_vsTAP");  testsel_mode = MONITOR_IMONI_I01U_TEMP;} if( mode == I_IMONI_FLASH_TEMP ) {s
      terminal = VSSMON_MON;
      change_reg = IN_ETLR09;
      for ( i=0 ; i<=127 ; i++ ) reg_code[i] = (0x0 + i) & 0x7F;
      mask  = 0x80;
      shift = 0;
      loop_st = 0;
      loop_ed = 127;
      break;
    case V_VHH_E_TEMP:
    // d(Vhh)x⏞
      sprintf(filename,"vhh(erase)_vsTEMP");
      testsel_mode = MONITOR_VHH_E;
      terminal = VCCMON_MON;
      change_reg = IN_ETLR13;
      for ( i=0 ; i<=15 ; i++ ) reg_code[i] = (0x0 + i) & 0x0F;
      shift = 4;
      // ͏4bit
      loop_st = 0;
      loop_ed = 15;
      break;
    case V_VHH_P_TEMP:
    // d(Vhh)x⏞
      sprintf(filename,"vhh(write)_vsTEMP");
      testsel_mode = MONITOR_VHH_P;
      terminal = VCCMON_MON;
      change_reg = IN_ETLR14;
      for ( i=0 ; i<=15 ; i++ ) reg_code[i] = (0x0 + i) & 0x0F;
      shift = 4;
      // ͏4bit
      loop_st = 0;
      loop_ed = 15;
      break;
    case V_VHH_P_TEMPV:
    // d(Vhh)x⏞
      sprintf(filename,"vhh(write)_vsTEMP");
      testsel_mode = MONITOR_VHH_P;
      terminal = VCCMON_MON;
      change_reg = IN_ETLR14;
      for ( i=0 ; i<=15 ; i++ ) reg_code[i] = (0x0 + i) & 0x0F;
      shift = 0;
      // d⏞͉4bit
      loop_st = 0;
      loop_ed = 15;
      break;
    case I_IMONI_TEMP:
    // d(Flash)x⏞
      sprintf(filename,"imoni-flash(temp)_vsTEMP");
      testsel_mode = MONITOR_IMONI_FLASH_TEMP;
      terminal = VSSMON_MON;
      change_reg = IN_ETLR12;
      for ( i=0 ; i<=15 ; i++ ) reg_code[i] = (0x0 + i) & 0x0F;
      shift = 0;
      // ͉4bit
      loop_st = 0;
      loop_ed = 15;
      break;
    case T_OSC32:
      sprintf(filename,"T_OSC32");
      change_reg = IN_ETLR10;
  	   testsel_mode = MONITOR_OSC32;
    	 SetValue(IN_LDATA0,param,268*10);
    	 // Target=270us(10*100ns=1us)
  	   for ( i=0 ; i<=127 ; i++ ) reg_code[i] = (0x0 + i) & 0x7F;
  	   mask  = 0x80;
      shift = 0;
      loop_st = 0;
      loop_ed = 127;
  	   break;
    case T_OSC1:
      sprintf(filename,"T_OSC1");
      change_reg = IN_ETLR11;
  	  	testsel_mode = MONITOR_OSC1;
      SetValue(IN_LDATA0,param,98*10);
      // Target=100us(10*100ns=1us)
	     for ( i=8 ; i<=15 ; i++ ) reg_code[i-8] = (0x0 + i) & 0x0F;
      for ( i=0 ; i<=7 ; i++ ) reg_code[i+8] = (0x0 + i) & 0x0F;
      mask  = 0xF0;
      shift = 0;
      loop_st = 0;
      loop_ed = 15;
      break;
    case T_READDELAY8_FLP0:
    case T_READDELAY8_FLI1:
    case T_READDELAY8_FLI2:
  	   if(mode ==T_READDELAY8_FLP0){
  	   	 sprintf(filename,"T_READDELAY8_FLP0");
        change_reg = IN_ETLR26;
  	   	 mask  = 0xF0;
        shift = 0;
  	   	 module_loop=0;
  	   }else if(mode ==T_READDELAY8_FLI1){
