,%d",current_data[5]); fprintf(Fptdata,",Ramdom_CHKA_ON ,%d",current_data[6]); fprintf(Fptdata,",Ramdom_CHKA_OFF,%d",current_data[7]); fprintf(Fptdata,","); delay_timer(5*1000); if( fclose( Fptdata ) ){ printf( "CloseDataOutFile Fptdata Close Err" ); exit( -99 ); } delay_timer(200); break;
     case 1:


