		//printf("VrsgMonitor_Repeat : selvol = %dmV",selvol);
	  vrsg_buff[i]=selvol;
        }
        result = VrsgAnalyze(&vrsg_buff[0], &Vanalyze);
				//printf("VrsgMonitor_Repeat : Vanalyze = %dmV",Vanalyze);

	if(result == PASS){
	  Vresult[j] = Vanalyze;
        }else{
	  Vresult[j] = 0;
	}

      }

      DeviceSpecificPowerDown();
      DeviceLevelsPowerDown();

  return(PASS);
}

